-- Generated by scripts/export-editorial-guides-sql.mjs
-- Canonical seed for R Guide editorial lists.

create table if not exists public.editorial_guides (
  id text primary key,
  slug text not null unique,
  category text not null,
  country text not null,
  city text,
  neighborhood text,
  list jsonb not null,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

alter table public.editorial_guides enable row level security;

create or replace function public.set_updated_at()
returns trigger
language plpgsql
as $$
begin
  new.updated_at = now();
  return new;
end;
$$;

drop trigger if exists editorial_guides_set_updated_at on public.editorial_guides;

create trigger editorial_guides_set_updated_at
before update on public.editorial_guides
for each row
execute function public.set_updated_at();

drop policy if exists "Editorial guides are readable" on public.editorial_guides;

create policy "Editorial guides are readable"
on public.editorial_guides
for select
using (true);

create index if not exists editorial_guides_category_idx on public.editorial_guides (category);
create index if not exists editorial_guides_country_city_idx on public.editorial_guides (country, city);
create index if not exists editorial_guides_neighborhood_idx on public.editorial_guides (neighborhood);
create index if not exists editorial_guides_list_gin_idx on public.editorial_guides using gin (list);

insert into public.editorial_guides (
  id,
  slug,
  category,
  country,
  city,
  neighborhood,
  list
)
values
  ('list-barcelona-top-parks', 'barcelona-top-parks-in-the-city', 'Nature', 'Spain', 'Barcelona', null, '{"id":"list-barcelona-top-parks","slug":"barcelona-top-parks-in-the-city","seoSlug":"best-parks","seoTitle":"Best Parks in Barcelona","seoDescription":"Best parks in Barcelona for Gaudi architecture, hilltop views, historic gardens, Ciutadella lawns, Montjuic walks, and green spaces worth saving.","title":"Green Escapes and Hilltop Views","description":"A Barcelona green-space route built around landmark parks, historic gardens, and major hilltop viewpoints, with a mix of architecture, culture, and city panoramas.","url":"https://www.google.com/maps/search/top+parks+in+barcelona","category":"Nature","location":{"city":"Barcelona","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-nature","name":"R Nature","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-17T00:00:00.000Z","stops":[{"id":"park-guell","name":"Parc Guell","coordinates":[41.4145,2.1527],"description":"Gaudi''s landmark hilltop park combines sculptural architecture, mosaic terraces, and elevated city views; part of the UNESCO-listed Works of Antoni Gaudi.","hours":{"default":"Daily ~9:30 AM-7:30 PM."}},{"id":"parc-de-la-ciutadella","name":"Parc de la Ciutadella","coordinates":[41.3888,2.186],"description":"Barcelona''s central 19th-century park, created after the old citadel and shaped for the 1888 Universal Exhibition, with the Cascada Monumental, lake boating, and broad lawns.","hours":{"default":"Daily ~10:00 AM-10:30 PM."}},{"id":"montjuic-park","name":"Montjuic Park","coordinates":[41.363,2.1679],"description":"A large hill park linking gardens, lookouts, and major cultural landmarks, from Montjuic Castle and MNAC to Olympic-era venues and botanical spaces.","hours":{"default":"Park 24h; gardens/sites ~10:00 AM-sunset."}},{"id":"parc-del-laberint-dhorta","name":"Parc del Laberint d''Horta","coordinates":[41.4397,2.1477],"description":"Barcelona''s oldest garden (late 18th century), known for its cypress maze, neoclassical design, romantic landscaping, and quieter setting near Collserola.","hours":{"winter":"10:00 AM-6:00 PM","spring":"10:00 AM-7:00 PM","summer":"10:00 AM-8:00 PM","fall":"10:00 AM-7:00 PM"}},{"id":"parc-de-cervantes","name":"Parc de Cervantes","coordinates":[41.3871,2.1123],"description":"Pedralbes park centered on one of Barcelona''s strongest rose collections, with more than 10,000 bushes and peak blooms from late spring into summer.","hours":{"default":"Daily 8:00 AM-sunset."}},{"id":"parc-del-guinardo-bunkers-del-carmel","name":"Parc del Guinardo / Bunkers del Carmel","coordinates":[41.4183,2.1527],"description":"Hilltop park-and-viewpoint area around Turó de la Rovira (Bunkers del Carmel), known for former anti-aircraft battery remains and wide 360-degree skyline views.","hours":{"default":"Park 24h; Bunkers ~8:30 AM-7:30 PM (night-restricted)."}}],"sources":[{"name":"Turisme de Barcelona - Parks & Gardens","url":"https://www.barcelonaturisme.com/wv3/en/page/32/parks-and-gardens.html"},{"name":"Ajuntament de Barcelona - Parks directory","url":"https://ajuntament.barcelona.cat/ecologiaurbana/en/services/the-city-works/parks-and-gardens"},{"name":"Lonely Planet - Best parks in Barcelona","url":"https://www.lonelyplanet.com/articles/best-parks-barcelona"},{"name":"Time Out - Best parks and gardens in Barcelona","url":"https://www.timeout.com/barcelona/things-to-do/best-parks-in-barcelona"},{"name":"Conde Nast Traveler - Barcelona destination","url":"https://www.cntraveler.com/destinations/barcelona"},{"name":"Park Guell official","url":"https://parkguell.barcelona/en"},{"name":"UNESCO - Works of Antoni Gaudi","url":"https://whc.unesco.org/en/list/320"},{"name":"Parc de la Ciutadella page","url":"https://www.barcelonaturisme.com/wv3/en/page/117/parc-de-la-ciutadella.html"},{"name":"Montjuic page","url":"https://www.barcelonaturisme.com/wv3/en/page/120/montjuic.html"},{"name":"Parc del Laberint d''Horta page","url":"https://www.barcelonaturisme.com/wv3/en/page/118/parc-del-laberint-dhorta.html"},{"name":"Parc de Cervantes page","url":"https://www.barcelonaturisme.com/wv3/en/page/119/parc-de-cervantes.html"},{"name":"Turo de la Rovira / Bunkers del Carmel page","url":"https://www.barcelonaturisme.com/wv3/en/page/124/turo-de-la-rovira.html"},{"name":"Google Maps","url":"https://maps.google.com"},{"name":"Tripadvisor - Barcelona parks attractions","url":"https://www.tripadvisor.com/Attractions-g187497-Activities-c57-Barcelona_Catalonia.html"}]}'::jsonb),
  ('list-barcelona-gothic-quarter-restaurants', 'barcelona-gothic-quarter-restaurants', 'Food', 'Spain', 'Barcelona', 'Gothic Quarter', '{"id":"list-barcelona-gothic-quarter-restaurants","slug":"barcelona-gothic-quarter-restaurants","seoSlug":"best-restaurants","seoTitle":"Best Restaurants in the Gothic Quarter, Barcelona","seoDescription":"Best restaurants in the Gothic Quarter, Barcelona, from historic Catalan dining rooms to modern tasting menus and old-town spots that avoid the tourist-trap pattern.","title":"Old-City Tables That Hold Up","description":"Gothic Quarter restaurants that avoid the old-town tourist trap pattern, from historic Catalan dining rooms to tight modern tasting menus.","url":"https://www.google.com/maps/search/gothic+quarter+restaurants+barcelona","category":"Food","location":{"city":"Barcelona","neighborhood":"Gothic Quarter","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-food","name":"R Food","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-29T00:00:00.000Z","stops":[{"id":"gothic-la-sosenga","name":"La Sosenga","coordinates":[41.3826,2.1749],"description":"Source cross-checks point to La Sosenga as one of the stronger food-first choices inside the Gothic Quarter: a small Catalan room that updates older recipes through seasonal, tasting-menu-style cooking rather than leaning on old-city atmosphere alone. Time Out and map-review signals support it as a better reservation for diners who want regional cooking, careful plating, and a quieter meal than the tourist-heavy lanes usually provide.","price":"$$","priceSource":"Time Out","hours":{"mon":"Closed","tue":"1:00 PM-4:00 PM","wed":"1:00 PM-4:00 PM","thu":"1:00 PM-4:00 PM","fri":"1:00 PM-4:00 PM, 8:00 PM-11:00 PM","sat":"1:00 PM-4:00 PM, 8:00 PM-11:00 PM","sun":"Closed"}},{"id":"gothic-bistrot-levante","name":"Bistrot Levante","coordinates":[41.3833,2.1769],"description":"Eater''s Old City coverage and Google Maps signals make Bistrot Levante useful as a modern counterpoint to the Gothic Quarter''s traditional taverns. The draw is not landmark history; it is a compact bistro on Placeta de Manuel Ribé with Eastern Mediterranean flavors, good vegetable-forward plates, and a calmer room that works for lunch or dinner when nearby streets are packed.","price":"$$","priceSource":"Eater / Google Maps","hours":{"mon":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","tue":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","wed":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","thu":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","fri":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sat":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sun":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM"}},{"id":"gothic-kak-koy","name":"Kak Koy","coordinates":[41.385,2.1755],"description":"Kak Koy is included as the high-end, source-backed alternative in the Gothic core: Eater highlights its robata approach, and map/booking signals show it functions more like a focused Japanese grill counter than a broad tapas stop. It is best for diners who want Barcelona seafood and market produce filtered through precise charcoal cooking, bar seating, and a reservation-led dinner rhythm.","price":"$$$","priceSource":"Eater / Google Maps","hours":{"mon":"Closed","tue":"7:00 PM-10:30 PM","wed":"7:00 PM-10:30 PM","thu":"7:00 PM-10:30 PM","fri":"7:00 PM-10:30 PM","sat":"7:00 PM-10:30 PM","sun":"Closed"}},{"id":"gothic-la-plata-restaurant","name":"Bar La Plata","coordinates":[41.3818,2.1799],"description":"Bar La Plata earns its spot through longevity, traveler-review consistency, and a menu that has stayed intentionally short since 1945. The value is the whole old-tavern package: fried fish, tomato salad, butifarra, house wine, fast counter service, and a room that still feels local despite being deep in the Gothic Quarter.","price":"$","priceSource":"Tripadvisor / Google Maps","hours":{"mon":"Closed","tue":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","wed":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","thu":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","fri":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","sat":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","sun":"Closed"}},{"id":"gothic-capet","name":"Capet","coordinates":[41.3816,2.1764],"description":"Capet is the polished small-restaurant pick in this set, supported by MICHELIN and reservation-platform signals rather than social hype. It works for a serious dinner in the Gothic lanes: contemporary Catalan cooking, a controlled chef-led menu, and enough intimacy to feel special without the scale or price jump of Barcelona''s major destination tasting rooms.","price":"$$$","priceSource":"MICHELIN Guide / Resy","hours":{"mon":"Closed","tue":"7:00 PM-10:30 PM","wed":"7:00 PM-10:30 PM","thu":"7:00 PM-10:30 PM","fri":"7:00 PM-10:30 PM","sat":"7:00 PM-10:30 PM","sun":"Closed"}},{"id":"gothic-sensi-bistro","name":"Sensi Bistro","coordinates":[41.3803,2.1771],"description":"Sensi Bistro stays on the list because Tripadvisor and Google Maps show sustained demand from visitors looking for creative tapas that are more composed than the surrounding old-city churn. It is group-friendly, shareable, and practical near Plaça Reial, with the caveat that it is more polished international bistro-tapas than a hidden local institution.","price":"$$","priceSource":"Tripadvisor / Google Maps","hours":{"mon":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","tue":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","wed":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","thu":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","fri":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sat":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sun":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM"}}],"sources":[{"name":"Time Out - Best restaurants in Barcelona","url":"https://www.timeout.com/barcelona/restaurants/best-restaurants-in-barcelona"},{"name":"The Infatuation - Best Restaurants in Barcelona","url":"https://www.theinfatuation.com/barcelona/guides/best-restaurants-hotels-barcelona"},{"name":"Eater - Old City restaurants","url":"https://www.eater.com/maps/barcelona-old-city-gothic-quarter-best-restaurants"},{"name":"MICHELIN Guide - Capet","url":"https://guide.michelin.com/us/en/catalunya/barcelona/restaurant/capet"},{"name":"Restaurants for Kings - Gothic Quarter restaurants","url":"https://restaurantsforkings.com/blog/gothic-quarter-barcelona-restaurants-guide-2026.html"},{"name":"Tripadvisor - Gothic Quarter restaurants","url":"https://www.tripadvisor.com/Restaurants-g187497-zfn7237169-Barcelona_Catalonia.html"},{"name":"Google Maps","url":"https://maps.google.com"}]}'::jsonb),
  ('list-barcelona-el-born-restaurants', 'barcelona-el-born-restaurants', 'Food', 'Spain', 'Barcelona', 'El Born', '{"id":"list-barcelona-el-born-restaurants","slug":"barcelona-el-born-restaurants","seoSlug":"best-restaurants","seoTitle":"Best Restaurants in El Born, Barcelona","seoDescription":"Best restaurants in El Born, Barcelona, including seafood counters, natural-wine rooms, tapas classics, market-adjacent kitchens, and booking-worthy local favorites.","title":"Cava, Counters, and Cool Rooms","description":"El Born restaurants with real pull: seafood counters, natural-wine rooms, market-adjacent kitchens, and tapas classics that still justify the crowd.","url":"https://www.google.com/maps/search/el+born+restaurants+barcelona","category":"Food","location":{"city":"Barcelona","neighborhood":"El Born","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-food","name":"R Food","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-29T00:00:00.000Z","stops":[{"id":"born-cal-pep-restaurant","name":"Cal Pep","coordinates":[41.3835,2.1839],"description":"Cal Pep is a Born classic repeatedly validated by editorial guides and traveler demand: the experience centers on the counter, rapid-fire seafood tapas, and letting the kitchen steer you through clams, squid, fried fish, and seasonal specials. It is expensive for the format, but the draw is the performance of the room as much as the food.","price":"$$$","priceSource":"The Infatuation / Google Maps","hours":{"mon":"Closed","tue":"1:00 PM-3:30 PM, 8:00 PM-11:00 PM","wed":"1:00 PM-3:30 PM, 8:00 PM-11:00 PM","thu":"1:00 PM-3:30 PM, 8:00 PM-11:00 PM","fri":"1:00 PM-3:30 PM, 8:00 PM-11:30 PM","sat":"1:00 PM-3:30 PM, 8:00 PM-11:30 PM","sun":"Closed"}},{"id":"born-bar-del-pla-restaurant","name":"Bar del Pla","coordinates":[41.3857,2.1817],"description":"Bar del Pla is supported by The Infatuation, Google Maps, and natural-wine chatter as one of El Born''s more reliable modern tapas rooms. It balances Catalan comfort, creative small plates, and a bistro-like wine program, making it a strong booking when you want the neighborhood''s energy without defaulting to a tourist-facing tapas counter.","price":"$$","priceSource":"The Infatuation / Google Maps","hours":{"mon":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","tue":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","wed":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","thu":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","fri":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sat":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sun":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM"}},{"id":"born-fismuler","name":"Fismuler","coordinates":[41.3867,2.1846],"description":"Fismuler is a higher-price Born pick because sources consistently frame it as a destination meal, not just a neighborhood stop. The appeal is raw seafood, seasonal Mediterranean plates, a stylish Rec Comtal dining room, and the now-famous cheesecake; it suits a longer dinner where design, wine, and pacing matter.","price":"$$$","priceSource":"The Infatuation / Google Maps","hours":{"mon":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","tue":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","wed":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","thu":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","fri":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sat":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sun":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM"}},{"id":"born-bar-brutal","name":"Bar Brutal","coordinates":[41.3849,2.1811],"description":"Bar Brutal is included for its natural-wine importance and continued social proof across editorial guides and geo-tagged dining posts. It is best for curious drinkers who want dinner to revolve around low-intervention bottles, lively service, and snackable plates, with the understanding that the wine culture is the main reason to go.","price":"$$","priceSource":"The Infatuation / Instagram","hours":{"mon":"7:00 PM-12:00 AM","tue":"7:00 PM-12:00 AM","wed":"7:00 PM-12:00 AM","thu":"7:00 PM-12:00 AM","fri":"1:00 PM-4:00 PM, 7:00 PM-12:30 AM","sat":"1:00 PM-4:00 PM, 7:00 PM-12:30 AM","sun":"1:00 PM-4:00 PM, 7:00 PM-12:00 AM"}},{"id":"born-cuines-santa-caterina","name":"Cuines Santa Caterina","coordinates":[41.3867,2.1788],"description":"Cuines Santa Caterina is the practical market-adjacent anchor in El Born: sources and review volume point to it as reliable rather than rare. Under the Santa Caterina market roof, it covers rice, noodles, grilled dishes, and broad all-day hours, making it useful for groups, mixed appetites, and days when fixed Spanish meal times are inconvenient.","price":"$$","priceSource":"The Infatuation / Google Maps","hours":{"mon":"12:00 PM-12:00 AM","tue":"12:00 PM-12:00 AM","wed":"12:00 PM-12:00 AM","thu":"12:00 PM-12:00 AM","fri":"12:00 PM-1:00 AM","sat":"12:00 PM-1:00 AM","sun":"12:00 PM-12:00 AM"}},{"id":"born-el-xampanyet-restaurant","name":"El Xampanyet","coordinates":[41.3847,2.1836],"description":"El Xampanyet is one of the clearest source-backed Born classics, with editorial guides and traveler reviews agreeing on the same strengths: cava, anchovies, conservas, simple tapas, and a room that is almost always crowded. Treat it as a short, loud, salty stop near the Picasso Museum rather than a slow sit-down dinner.","price":"$","priceSource":"The Infatuation / Tripadvisor","hours":{"mon":"7:00 PM-11:00 PM","tue":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","wed":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","thu":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","fri":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","sat":"12:00 PM-3:30 PM","sun":"Closed"}}],"sources":[{"name":"The Infatuation - El Born","url":"https://www.theinfatuation.com/barcelona/neighborhoods/el-born"},{"name":"The Infatuation - Best Restaurants in Barcelona","url":"https://www.theinfatuation.com/barcelona/guides/best-restaurants-hotels-barcelona"},{"name":"Eater - Old City restaurants","url":"https://www.eater.com/maps/barcelona-old-city-gothic-quarter-best-restaurants"},{"name":"Time Out - Barcelona restaurants","url":"https://www.timeout.com/barcelona/restaurants"},{"name":"Tripadvisor - Barcelona restaurants","url":"https://www.tripadvisor.com/Restaurants-g187497-Barcelona_Catalonia.html"},{"name":"Google Maps","url":"https://maps.google.com"}]}'::jsonb),
  ('list-barcelona-eixample-restaurants', 'barcelona-eixample-restaurants', 'Food', 'Spain', 'Barcelona', 'Eixample', '{"id":"list-barcelona-eixample-restaurants","slug":"barcelona-eixample-restaurants","seoSlug":"best-restaurants","seoTitle":"Best Restaurants in Eixample, Barcelona","seoDescription":"Best restaurants in Eixample, Barcelona, from destination tasting menus and polished tapas counters to design-hotel dining rooms and reliable group-friendly classics.","title":"Big-Deal Tables and Tapas","description":"Eixample dining picks across destination tasting menus, polished tapas counters, hotel dining rooms, and reliable group-friendly classics.","url":"https://www.google.com/maps/search/eixample+restaurants+barcelona","category":"Food","location":{"city":"Barcelona","neighborhood":"Eixample","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-food","name":"R Food","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-29T00:00:00.000Z","stops":[{"id":"eixample-disfrutar","name":"Disfrutar","coordinates":[41.3878,2.1533],"description":"Disfrutar is the global destination restaurant in this data set, supported by MICHELIN''s top recognition and World''s 50 Best placement. The elBulli-alumni kitchen is known for highly technical, playful tasting menus, so it belongs in the expensive filter and should be framed as a trip-defining reservation rather than a neighborhood dinner.","price":"$$$","priceSource":"MICHELIN Guide / World''s 50 Best","hours":{"mon":"Closed","tue":"1:00 PM-2:15 PM, 8:00 PM-9:15 PM","wed":"1:00 PM-2:15 PM, 8:00 PM-9:15 PM","thu":"1:00 PM-2:15 PM, 8:00 PM-9:15 PM","fri":"1:00 PM-2:15 PM, 8:00 PM-9:15 PM","sat":"1:00 PM-2:15 PM, 8:00 PM-9:15 PM","sun":"Closed"}},{"id":"eixample-bar-mut-restaurant","name":"Bar Mut","coordinates":[41.3917,2.1554],"description":"Bar Mut is a polished Eixample bistro pick with strong guide and map signals around wine, seasonal Catalan plates, and late lunch-to-dinner demand near Passeig de Gràcia. It is pricier than a casual tapas bar, but useful when travelers want a classic Barcelona room that still feels compact and food-focused.","price":"$$$","priceSource":"The Infatuation / Google Maps","hours":{"mon":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","tue":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","wed":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","thu":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","fri":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sat":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sun":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM"}},{"id":"eixample-bodega-bonay","name":"Bodega Bonay","coordinates":[41.3918,2.1746],"description":"Bodega Bonay is included because The Infatuation and reservation signals position it as one of Eixample''s better hotel-linked dining rooms. The draw is Casa Bonay''s design ecosystem: natural wine, anchovies, cecina, pastas, and long lunches that feel stylish without requiring a tasting menu.","price":"$$","priceSource":"The Infatuation / Resy","hours":{"mon":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","tue":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","wed":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","thu":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","fri":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sat":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sun":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM"}},{"id":"eixample-paco-meralgo","name":"Paco Meralgo","coordinates":[41.3915,2.1519],"description":"Paco Meralgo is the reliable mid-range tapas counter for Eixample, backed more by review volume and practical usefulness than by novelty. It works when diners want croquettes, bombas, seafood, and quick service in a polished room, especially when higher-profile reservations are unavailable.","price":"$$","priceSource":"Google Maps / Tripadvisor","hours":{"mon":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","tue":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","wed":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","thu":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","fri":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sat":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sun":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM"}},{"id":"eixample-cerveceria-catalana","name":"Cervecería Catalana","coordinates":[41.3921,2.1602],"description":"Cervecería Catalana remains on the list because Google Maps and Tripadvisor volume confirm its role as a high-demand tapas machine. It is not hidden, but it is consistent: fast counter service, montaditos, seafood, tortillas, and a wait that is often part of the experience rather than a sign to abandon the plan.","price":"$$","priceSource":"Google Maps / Tripadvisor","hours":{"mon":"12:00 PM-12:00 AM","tue":"12:00 PM-12:00 AM","wed":"12:00 PM-12:00 AM","thu":"12:00 PM-12:00 AM","fri":"12:00 PM-1:00 AM","sat":"12:00 PM-1:00 AM","sun":"12:00 PM-12:00 AM"}},{"id":"eixample-el-nacional-restaurant","name":"El Nacional","coordinates":[41.3917,2.168],"description":"El Nacional is best understood as a logistics and atmosphere pick rather than a critic''s secret. Time Out and map data support it as a central, visually memorable food hall with separate counters for meat, seafood, tapas, and drinks, making it especially useful for groups near Passeig de Gràcia.","price":"$$","priceSource":"Time Out / Google Maps","hours":{"mon":"12:00 PM-12:00 AM","tue":"12:00 PM-12:00 AM","wed":"12:00 PM-12:00 AM","thu":"12:00 PM-12:00 AM","fri":"12:00 PM-1:00 AM","sat":"12:00 PM-1:00 AM","sun":"12:00 PM-12:00 AM"}}],"sources":[{"name":"The Infatuation - Best Restaurants in Eixample","url":"https://www.theinfatuation.com/barcelona/guides/best-restaurants-eixample"},{"name":"The Infatuation - Best Restaurants in Barcelona","url":"https://www.theinfatuation.com/barcelona/guides/best-restaurants-hotels-barcelona"},{"name":"Eater - Best Restaurants in Barcelona","url":"https://www.eater.com/maps/best-restaurants-barcelona-spain"},{"name":"MICHELIN Guide - Disfrutar","url":"https://guide.michelin.com/us/en/catalunya/barcelona/restaurant/disfrutar"},{"name":"World''s 50 Best - Disfrutar","url":"https://www.theworlds50best.com/discovery/Establishments/Spain/Barcelona/Disfrutar.html"},{"name":"Time Out - Best restaurants in Barcelona","url":"https://www.timeout.com/barcelona/restaurants/best-restaurants-in-barcelona"},{"name":"Tripadvisor - Barcelona restaurants","url":"https://www.tripadvisor.com/Restaurants-g187497-Barcelona_Catalonia.html"},{"name":"Barcelonaando - Eixample guide","url":"https://barcelonando.com/eixample/"},{"name":"Google Maps","url":"https://maps.google.com"}]}'::jsonb),
  ('list-barcelona-gracia-restaurants', 'barcelona-gracia-restaurants', 'Food', 'Spain', 'Barcelona', 'Gràcia', '{"id":"list-barcelona-gracia-restaurants","slug":"barcelona-gracia-restaurants","seoSlug":"best-restaurants","seoTitle":"Best Restaurants in Gràcia, Barcelona","seoDescription":"Best restaurants in Gràcia, Barcelona, covering chef-led rooms, market lunches, creative tapas, casual local favorites, and neighborhood dining worth booking.","title":"Village Tables Worth the Walk","description":"Gràcia restaurants that match the neighborhood''s village rhythm: chef-led rooms, market lunches, creative tapas, and unfussy local favorites.","url":"https://www.google.com/maps/search/gracia+restaurants+barcelona","category":"Food","location":{"city":"Barcelona","neighborhood":"Gràcia","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-food","name":"R Food","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-29T00:00:00.000Z","stops":[{"id":"gracia-bemba","name":"Bemba Smash Burger","coordinates":[41.407,2.1583],"description":"Bemba earns the cheap-eats slot because current Eater coverage and social geo-tags point to it as a focused Gràcia burger counter rather than a generic fast-food option. The appeal is a tight smash-burger menu, quality patties, house pickles, and quick execution in a neighborhood otherwise dominated by tapas and sit-down rooms.","price":"$","priceSource":"Eater / Instagram","hours":{"mon":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","tue":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","wed":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","thu":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","fri":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sat":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sun":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM"}},{"id":"gracia-con-gracia","name":"Con Gracia","coordinates":[41.3979,2.1599],"description":"Con Gracia is the neighborhood''s special-occasion restaurant in this set, supported by Time Out and strong map signals for tasting-menu dining. It suits travelers who want a quieter Gràcia dinner with wine pairing, chef-led pacing, and more polish than the plaza bars, while staying smaller than Eixample''s headline fine-dining rooms.","price":"$$$","priceSource":"Time Out / Google Maps","hours":{"mon":"Closed","tue":"7:00 PM-10:30 PM","wed":"7:00 PM-10:30 PM","thu":"7:00 PM-10:30 PM","fri":"7:00 PM-10:30 PM","sat":"7:00 PM-10:30 PM","sun":"Closed"}},{"id":"gracia-la-pubilla","name":"La Pubilla","coordinates":[41.4025,2.1534],"description":"La Pubilla is included for its market-facing Catalan cooking and sustained local/traveler review strength. The best use case is breakfast or lunch near Mercat de la Llibertat, where the food reads as daily neighborhood cooking rather than destination theatrics: stews, eggs, seasonal plates, and a room that turns over with regulars.","price":"$$","priceSource":"Tripadvisor / Google Maps","hours":{"mon":"8:30 AM-4:00 PM","tue":"8:30 AM-4:00 PM","wed":"8:30 AM-4:00 PM","thu":"8:30 AM-4:00 PM","fri":"8:30 AM-4:00 PM","sat":"9:00 AM-4:00 PM","sun":"Closed"}},{"id":"gracia-gut","name":"Gut","coordinates":[41.4002,2.1568],"description":"Gut is the softer, lighter Gràcia option, supported by Time Out and map data for Mediterranean-Asian plates, vegetables, and gluten-free or health-conscious flexibility. It is useful when the group wants something brighter than fried tapas without leaving the neighborhood''s relaxed evening rhythm.","price":"$$","priceSource":"Time Out / Google Maps","hours":{"mon":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","tue":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","wed":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","thu":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","fri":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sat":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sun":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM"}},{"id":"gracia-la-panxa-del-bisbe","name":"La Panxa del Bisbe","coordinates":[41.4031,2.1549],"description":"La Panxa del Bisbe is a small creative tapas room that sources frame as more personal than the surrounding plaza bars. It is best for diners who still want a shareable Catalan format but with more attention to composition, seasonal specials, and a room small enough that booking matters.","price":"$$","priceSource":"Time Out / Google Maps","hours":{"mon":"Closed","tue":"1:00 PM-3:30 PM, 8:00 PM-11:00 PM","wed":"1:00 PM-3:30 PM, 8:00 PM-11:00 PM","thu":"1:00 PM-3:30 PM, 8:00 PM-11:00 PM","fri":"1:00 PM-3:30 PM, 8:00 PM-11:30 PM","sat":"1:00 PM-3:30 PM, 8:00 PM-11:30 PM","sun":"Closed"}},{"id":"gracia-shoronpo","name":"Shoronpo","coordinates":[41.3981,2.1572],"description":"Shoronpo is included as a newer Gràcia food hit confirmed through Eater and social geo-tag momentum. It gives the neighborhood list a non-tapas option: ramen, soup dumplings, tantanmen, and fried snacks in a busy room where demand suggests planning ahead rather than treating it as a casual fallback.","price":"$$","priceSource":"Eater / Instagram","hours":{"mon":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","tue":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","wed":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","thu":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","fri":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sat":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sun":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM"}}],"sources":[{"name":"Time Out - Gràcia guide","url":"https://www.timeout.com/barcelona/things-to-do/gracia"},{"name":"Time Out - Con Gracia","url":"https://www.timeout.com/barcelona/restaurants/con-gracia"},{"name":"Eater - Best Restaurants in Barcelona","url":"https://www.eater.com/maps/best-restaurants-barcelona-spain"},{"name":"The Infatuation - Barcelona guides","url":"https://www.theinfatuation.com/barcelona/guides"},{"name":"Tripadvisor - La Pubilla","url":"https://www.tripadvisor.com/Restaurant_Review-g187497-d3800375-Reviews-La_Pubilla-Barcelona_Catalonia.html"},{"name":"Google Maps","url":"https://maps.google.com"}]}'::jsonb),
  ('list-barcelona-poble-sec-restaurants', 'barcelona-poble-sec-restaurants', 'Food', 'Spain', 'Barcelona', 'Poble-sec', '{"id":"list-barcelona-poble-sec-restaurants","slug":"barcelona-poble-sec-restaurants","seoSlug":"best-restaurants","seoTitle":"Best Restaurants in Poble-sec, Barcelona","seoDescription":"Best restaurants in Poble-sec, Barcelona, for serious tapas, Montjuic-view rice, Venetian-Catalan plates, and dinner stops near theaters and Sala Apolo.","title":"Blai Bites and Montjuïc Meals","description":"Poble-sec restaurants for serious tapas, Montjuic-view rice, Venetian-Catalan plates, and dinner stops that make sense before theater or Apolo.","url":"https://www.google.com/maps/search/poble+sec+restaurants+barcelona","category":"Food","location":{"city":"Barcelona","neighborhood":"Poble-sec","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-food","name":"R Food","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-29T00:00:00.000Z","stops":[{"id":"poblesec-quimet-quimet-restaurant","name":"Quimet & Quimet","coordinates":[41.3738,2.1635],"description":"Quimet & Quimet is one of Poble-sec''s most source-consistent food stops, supported by its own current hours, traveler reviews, and long-running editorial reputation. It is standing-room only, built around montaditos layered with smoked, preserved, and tinned ingredients, and works best as an early, focused stop with no expectation of lingering.","price":"$$","priceSource":"Official site / Tripadvisor","hours":{"mon":"12:00 PM-4:00 PM, 6:00 PM-10:30 PM","tue":"12:00 PM-4:00 PM, 6:00 PM-10:30 PM","wed":"12:00 PM-4:00 PM, 6:00 PM-10:30 PM","thu":"12:00 PM-4:00 PM, 6:00 PM-10:30 PM","fri":"12:00 PM-4:00 PM, 6:00 PM-10:30 PM","sat":"Closed","sun":"Closed"}},{"id":"poblesec-martinez","name":"Martínez","coordinates":[41.3692,2.1661],"description":"Martínez is the expensive Poble-sec/Montjuïc meal because sources frame it around terrace setting, seafood rice, and city-port views. It is less about neighborhood grit and more about a planned daytime reservation: paella, fideuà, Catalan wine, and a long lunch above the city.","price":"$$$","priceSource":"Eater / The Infatuation","hours":{"mon":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","tue":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","wed":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","thu":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","fri":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sat":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sun":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM"}},{"id":"poblesec-xemei","name":"Xemei","coordinates":[41.3718,2.1668],"description":"Xemei is a Venetian-leaning Barcelona favorite with support from Eater-style city guides and local food coverage. It adds range to Poble-sec with seafood, pastas, and Italian-Adriatic flavors, while the room keeps the slightly chaotic, lively feel that fits the neighborhood better than a formal fine-dining setup.","price":"$$","priceSource":"Eater / El País","hours":{"mon":"Closed","tue":"1:00 PM-3:30 PM, 8:00 PM-11:00 PM","wed":"1:00 PM-3:30 PM, 8:00 PM-11:00 PM","thu":"1:00 PM-3:30 PM, 8:00 PM-11:00 PM","fri":"1:00 PM-3:30 PM, 8:00 PM-11:30 PM","sat":"1:00 PM-3:30 PM, 8:00 PM-11:30 PM","sun":"Closed"}},{"id":"poblesec-la-platilleria-restaurant","name":"La Platilleria","coordinates":[41.3746,2.1658],"description":"La Platilleria is the warm small-plates choice for a Poble-sec dinner that does not need to become a full tasting-menu event. Review signals support it for approachable service, compact plates, and a location that works before theater, after Montjuïc, or as a calmer alternative to the busiest Carrer de Blai stops.","price":"$$","priceSource":"Google Maps / Tripadvisor","hours":{"mon":"Closed","tue":"1:00 PM-3:30 PM, 8:00 PM-11:00 PM","wed":"1:00 PM-3:30 PM, 8:00 PM-11:00 PM","thu":"1:00 PM-3:30 PM, 8:00 PM-11:00 PM","fri":"1:00 PM-3:30 PM, 8:00 PM-11:30 PM","sat":"1:00 PM-3:30 PM, 8:00 PM-11:30 PM","sun":"Closed"}},{"id":"poblesec-margarit","name":"Margarit","coordinates":[41.3732,2.1646],"description":"Margarit is a newer Poble-sec pick validated by Eater and social geo-tags, useful because it brings Mediterranean-Greek cooking and natural-wine energy to the Montjuïc slope. The appeal is dips, grilled vegetables, seafood, and a relaxed room that feels current without drifting into hype-only territory.","price":"$$","priceSource":"Eater / Instagram","hours":{"mon":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","tue":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","wed":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","thu":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","fri":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sat":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sun":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM"}},{"id":"poblesec-mano-rota","name":"Mano Rota","coordinates":[41.374,2.1681],"description":"Mano Rota is the chef-driven Poble-sec reservation, included for its creative Latin American and Mediterranean tasting-menu approach and strong local review profile. It belongs in the expensive filter because the experience is more structured, ambitious, and dinner-focused than the neighborhood''s pintxos and tavern circuit.","price":"$$$","priceSource":"Barcelona Metropolitan / Google Maps","hours":{"mon":"Closed","tue":"7:00 PM-10:30 PM","wed":"7:00 PM-10:30 PM","thu":"7:00 PM-10:30 PM","fri":"7:00 PM-10:30 PM","sat":"7:00 PM-10:30 PM","sun":"Closed"}}],"sources":[{"name":"The Infatuation - Best Restaurants in Barcelona","url":"https://www.theinfatuation.com/barcelona/guides/best-restaurants-hotels-barcelona"},{"name":"Eater - Best Restaurants in Barcelona","url":"https://www.eater.com/maps/best-restaurants-barcelona-spain"},{"name":"Time Out - Barcelona restaurants","url":"https://www.timeout.com/barcelona/restaurants"},{"name":"Time Out - Poble-sec bars","url":"https://www.timeout.com/barcelona/bars-and-pubs/poble-sec-bars"},{"name":"Quimet & Quimet official","url":"https://quimetiquimet.com/en/"},{"name":"Tripadvisor - Quimet & Quimet","url":"https://www.tripadvisor.com/Restaurant_Review-g187497-d717377-Reviews-Quimet_Quimet-Barcelona_Catalonia.html"},{"name":"Google Maps","url":"https://maps.google.com"}]}'::jsonb),
  ('list-barcelona-citywide-restaurants', 'barcelona-citywide-restaurants', 'Food', 'Spain', 'Barcelona', null, '{"id":"list-barcelona-citywide-restaurants","slug":"barcelona-citywide-restaurants","seoSlug":"best-restaurants","seoTitle":"Best Restaurants in Barcelona","seoDescription":"Best restaurants in Barcelona, from world-class tasting menus and seafood counters to natural-wine rooms, tavern classics, market lunches, and neighborhood meals worth crossing town for.","title":"Tables Worth Crossing Town For","description":"A citywide Barcelona restaurant shortlist built from the strongest neighborhood picks: destination tasting menus, old taverns, counter seafood, natural-wine rooms, and practical meals that still feel specific to the city.","url":"https://www.google.com/maps/search/best+restaurants+barcelona","category":"Food","location":{"city":"Barcelona","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-food","name":"R Food","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-05-02T00:00:00.000Z","stops":[{"id":"citywide-disfrutar","name":"Disfrutar","coordinates":[41.3878,2.1533],"description":"Disfrutar is the citywide special-occasion anchor because MICHELIN and World''s 50 Best both support its status as Barcelona''s global fine-dining reference. The meal is a technical, playful tasting-menu commitment from elBulli alumni, so it belongs in the expensive filter and should be planned as the trip-defining reservation rather than a flexible dinner stop.","price":"$$$","priceSource":"MICHELIN Guide / World''s 50 Best","hours":{"mon":"Closed","tue":"1:00 PM-2:15 PM, 8:00 PM-9:15 PM","wed":"1:00 PM-2:15 PM, 8:00 PM-9:15 PM","thu":"1:00 PM-2:15 PM, 8:00 PM-9:15 PM","fri":"1:00 PM-2:15 PM, 8:00 PM-9:15 PM","sat":"1:00 PM-2:15 PM, 8:00 PM-9:15 PM","sun":"Closed"}},{"id":"citywide-cal-pep","name":"Cal Pep","coordinates":[41.3835,2.1839],"description":"Cal Pep represents the Born seafood-counter experience that still justifies the demand: fast pacing, tight seating, and a kitchen-led progression through clams, squid, fried fish, and seasonal tapas. The Infatuation and map-review signals back it as expensive for the format but valuable when the room''s performance is part of the meal.","price":"$$$","priceSource":"The Infatuation / Google Maps","hours":{"mon":"Closed","tue":"1:00 PM-3:30 PM, 8:00 PM-11:00 PM","wed":"1:00 PM-3:30 PM, 8:00 PM-11:00 PM","thu":"1:00 PM-3:30 PM, 8:00 PM-11:00 PM","fri":"1:00 PM-3:30 PM, 8:00 PM-11:30 PM","sat":"1:00 PM-3:30 PM, 8:00 PM-11:30 PM","sun":"Closed"}},{"id":"citywide-quimet-quimet","name":"Quimet & Quimet","coordinates":[41.3738,2.1635],"description":"Quimet & Quimet is the classic Poble-sec stop that earns citywide placement because official hours, Time Out, traveler reviews, and long-running food-guide consensus all point to the same thing: a tiny standing-room bodega built around montaditos, conservas, beer, and vermouth. Go early and treat it as a focused pre-dinner stop, not a lingering restaurant.","price":"$$","priceSource":"Official site / Time Out / Tripadvisor","hours":{"mon":"12:00 PM-4:00 PM, 6:00 PM-10:30 PM","tue":"12:00 PM-4:00 PM, 6:00 PM-10:30 PM","wed":"12:00 PM-4:00 PM, 6:00 PM-10:30 PM","thu":"12:00 PM-4:00 PM, 6:00 PM-10:30 PM","fri":"12:00 PM-4:00 PM, 6:00 PM-10:30 PM","sat":"Closed","sun":"Closed"}},{"id":"citywide-bar-del-pla","name":"Bar del Pla","coordinates":[41.3857,2.1817],"description":"Bar del Pla is the modern tapas-and-wine pick for travelers who want El Born energy without defaulting to the loudest old-city counters. The Infatuation, Google Maps, and natural-wine source signals support it for creative Catalan small plates, a bistro rhythm, and a reservation-worthy room that works for a real dinner.","price":"$$","priceSource":"The Infatuation / Google Maps","hours":{"mon":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","tue":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","wed":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","thu":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","fri":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sat":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sun":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM"}},{"id":"citywide-bodega-bonay","name":"Bodega Bonay","coordinates":[41.3918,2.1746],"description":"Bodega Bonay gives the citywide list a stylish Eixample lunch or dinner that does not require tasting-menu money. The Infatuation''s 2026 review and reservation signals frame it around Casa Bonay''s design-hotel ecosystem, Catalan natural wine, anchovies, cured meats, pastas, and a social long-lunch scene.","price":"$$","priceSource":"The Infatuation / TheFork","hours":{"mon":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","tue":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","wed":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","thu":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","fri":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sat":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sun":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM"}},{"id":"citywide-la-sosenga","name":"La Sosenga","coordinates":[41.3826,2.1749],"description":"La Sosenga is the Gothic Quarter safeguard against generic old-town dining: a small Catalan room where the reason to book is seasonal cooking and a calmer pace, not just location. Time Out and map-review validation make it useful for diners who want regional flavor and careful plating inside the tourist-heavy core.","price":"$$","priceSource":"Time Out / Google Maps","hours":{"mon":"Closed","tue":"1:00 PM-4:00 PM","wed":"1:00 PM-4:00 PM","thu":"1:00 PM-4:00 PM","fri":"1:00 PM-4:00 PM, 8:00 PM-11:00 PM","sat":"1:00 PM-4:00 PM, 8:00 PM-11:00 PM","sun":"Closed"}},{"id":"citywide-bar-la-plata","name":"Bar La Plata","coordinates":[41.3818,2.1799],"description":"Bar La Plata is the cheap classic because its value is unusually clear: a short menu, fried fish, tomato salad, butifarra, house wine, and a Gothic Quarter room that has not inflated itself into a concept. Tripadvisor and Google Maps support it as a practical old-tavern stop when the plan needs something quick, local-feeling, and low-fuss.","price":"$","priceSource":"Tripadvisor / Google Maps","hours":{"mon":"Closed","tue":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","wed":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","thu":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","fri":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","sat":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","sun":"Closed"}},{"id":"citywide-la-pubilla","name":"La Pubilla","coordinates":[41.4025,2.1534],"description":"La Pubilla is the Gràcia market-lunch pick, useful because it shows Barcelona''s daily Catalan cooking away from the old-city circuit. The support is more practical than hype-driven: sustained review strength, Mercat de la Llibertat proximity, stews, eggs, seasonal plates, and daytime hours that make it best for breakfast or lunch.","price":"$$","priceSource":"Tripadvisor / Google Maps","hours":{"mon":"8:30 AM-4:00 PM","tue":"8:30 AM-4:00 PM","wed":"8:30 AM-4:00 PM","thu":"8:30 AM-4:00 PM","fri":"8:30 AM-4:00 PM","sat":"9:00 AM-4:00 PM","sun":"Closed"}},{"id":"citywide-martinez","name":"Martínez","coordinates":[41.3692,2.1661],"description":"Martínez is the citywide long-lunch pick for seafood rice, terrace setting, and Montjuïc-to-port views. Eater and The Infatuation-style source signals make it less a neighborhood tavern and more a planned daytime reservation where paella, fideuà, Catalan wine, and the view are the point.","price":"$$$","priceSource":"Eater / The Infatuation","hours":{"mon":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","tue":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","wed":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","thu":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","fri":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sat":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sun":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM"}},{"id":"citywide-bemba","name":"Bemba Smash Burger","coordinates":[41.407,2.1583],"description":"Bemba is the cheap, current counterweight to Barcelona''s tapas-heavy shortlists. Eater and social geo-tag signals support it as a focused Gràcia smash-burger stop with quality patties, house pickles, and quick execution, best used when the day needs a casual meal that still feels chosen.","price":"$","priceSource":"Eater / Instagram","hours":{"mon":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","tue":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","wed":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","thu":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","fri":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sat":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sun":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM"}},{"id":"citywide-bar-brutal","name":"Bar Brutal","coordinates":[41.3849,2.1811],"description":"Bar Brutal earns a citywide slot for natural-wine culture as much as for food. Editorial, social, and map signals make it a strong dinner for curious drinkers who want low-intervention bottles, lively service, and snackable plates in El Born, with the caveat that wine is the main reason to choose it.","price":"$$","priceSource":"The Infatuation / Instagram","hours":{"mon":"7:00 PM-12:00 AM","tue":"7:00 PM-12:00 AM","wed":"7:00 PM-12:00 AM","thu":"7:00 PM-12:00 AM","fri":"1:00 PM-4:00 PM, 7:00 PM-12:30 AM","sat":"1:00 PM-4:00 PM, 7:00 PM-12:30 AM","sun":"1:00 PM-4:00 PM, 7:00 PM-12:00 AM"}},{"id":"citywide-capet","name":"Capet","coordinates":[41.3816,2.1764],"description":"Capet is the polished small-room alternative to Barcelona''s famous tasting-menu destinations. MICHELIN and reservation-platform signals support it for contemporary Catalan cooking in the Gothic lanes, so it belongs in the expensive filter but stays useful for travelers who want intimacy and control rather than a headline restaurant production.","price":"$$$","priceSource":"MICHELIN Guide / Resy","hours":{"mon":"Closed","tue":"7:00 PM-10:30 PM","wed":"7:00 PM-10:30 PM","thu":"7:00 PM-10:30 PM","fri":"7:00 PM-10:30 PM","sat":"7:00 PM-10:30 PM","sun":"Closed"}}],"sources":[{"name":"Eater - Best Restaurants in Barcelona","url":"https://www.eater.com/maps/best-restaurants-barcelona-spain"},{"name":"Eater - Old City restaurants","url":"https://www.eater.com/maps/barcelona-old-city-gothic-quarter-best-restaurants"},{"name":"The Infatuation - Best Restaurants in Barcelona","url":"https://www.theinfatuation.com/barcelona/guides/best-restaurants-hotels-barcelona"},{"name":"The Infatuation - Bodega Bonay","url":"https://www.theinfatuation.com/barcelona/reviews/bodega-bonay"},{"name":"Time Out - Best restaurants in Barcelona","url":"https://www.timeout.com/barcelona/restaurants/best-restaurants-in-barcelona"},{"name":"Time Out - Quimet i Quimet","url":"https://www.timeout.com/barcelona/restaurants/quimet-i-quimet"},{"name":"MICHELIN Guide - Disfrutar","url":"https://guide.michelin.com/us/en/catalunya/barcelona/restaurant/disfrutar"},{"name":"MICHELIN Guide - Capet","url":"https://guide.michelin.com/us/en/catalunya/barcelona/restaurant/capet"},{"name":"World''s 50 Best - Disfrutar","url":"https://www.theworlds50best.com/discovery/Establishments/Spain/Barcelona/Disfrutar.html"},{"name":"Quimet & Quimet official","url":"https://quimetiquimet.com/en/"},{"name":"Tripadvisor - Barcelona restaurants","url":"https://www.tripadvisor.com/Restaurants-g187497-Barcelona_Catalonia.html"},{"name":"Google Maps","url":"https://maps.google.com"}]}'::jsonb),
  ('list-barcelona-gothic-quarter-culture', 'barcelona-gothic-quarter-culture', 'Culture', 'Spain', 'Barcelona', 'Gothic Quarter', '{"id":"list-barcelona-gothic-quarter-culture","slug":"barcelona-gothic-quarter-culture","seoSlug":"best-museums-and-cultural-stops","seoTitle":"Best Museums and Cultural Stops in the Gothic Quarter, Barcelona","seoDescription":"Best museums and cultural stops in the Gothic Quarter, Barcelona, including Roman Barcino layers, cathedral streets, civic landmarks, and historic squares.","title":"Roman Stones and Cathedral Shadows","description":"Old-city cultural stops in the Gothic Quarter, built around Roman layers, cathedral streets, civic history, and intimate historic squares.","url":"https://www.google.com/maps/search/gothic+quarter+culture+barcelona","category":"Culture","location":{"city":"Barcelona","neighborhood":"Gothic Quarter","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-culture","name":"R Culture","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-29T00:00:00.000Z","stops":[{"id":"gothic-barcelona-cathedral","name":"Barcelona Cathedral","coordinates":[41.3839,2.1762],"description":"Barcelona Cathedral is the Gothic Quarter''s anchor because official tourism sources and visitor guides consistently use it to explain the neighborhood''s medieval identity. The visit is not only the nave: the cloister, choir, rooftop, geese, and surrounding cathedral square make it the best single stop for understanding how religious architecture shapes the old-city street pattern.","hours":{"mon":"9:00 AM-8:00 PM","tue":"9:00 AM-8:00 PM","wed":"9:00 AM-8:00 PM","thu":"9:00 AM-8:00 PM","fri":"9:00 AM-8:00 PM","sat":"9:00 AM-8:00 PM","sun":"9:00 AM-8:00 PM"}},{"id":"gothic-muhba-placa-del-rei","name":"MUHBA Plaça del Rei","coordinates":[41.3845,2.1777],"description":"MUHBA Plaça del Rei is included for its unusually clear layering of Roman Barcino and medieval Barcelona. Official museum material highlights the underground archaeological route, palace halls, and royal-city context, making this one of the strongest stops for travelers who want the Gothic Quarter to feel historically legible rather than just atmospheric.","hours":{"mon":"Closed","tue":"10:00 AM-7:00 PM","wed":"10:00 AM-7:00 PM","thu":"10:00 AM-7:00 PM","fri":"10:00 AM-7:00 PM","sat":"10:00 AM-7:00 PM","sun":"10:00 AM-7:00 PM"}},{"id":"gothic-temple-august","name":"Temple of Augustus","coordinates":[41.3842,2.1776],"description":"The Temple of Augustus is a compact but high-value Roman stop, supported by Barcelona history sources because it reveals four surviving columns inside a medieval courtyard. It works best as a quick cultural detour: a small, quiet reminder that the Gothic Quarter''s narrow lanes sit directly on top of the Roman city.","hours":{"mon":"Closed","tue":"10:00 AM-7:00 PM","wed":"10:00 AM-7:00 PM","thu":"10:00 AM-7:00 PM","fri":"10:00 AM-7:00 PM","sat":"10:00 AM-7:00 PM","sun":"10:00 AM-7:00 PM"}},{"id":"gothic-placa-sant-felip-neri","name":"Plaça de Sant Felip Neri","coordinates":[41.3834,2.1752],"description":"Plaça de Sant Felip Neri is here because guide sources repeatedly call out its emotional and architectural weight. The square combines Baroque stonework, schoolyard quiet, and visible Civil War damage, so it gives the old city a more reflective pause than the busier cathedral and Plaça Reial circuits.","hours":{"mon":"Open public space","tue":"Open public space","wed":"Open public space","thu":"Open public space","fri":"Open public space","sat":"Open public space","sun":"Open public space"}},{"id":"gothic-palau-generalitat","name":"Palau de la Generalitat","coordinates":[41.3829,2.1771],"description":"Palau de la Generalitat belongs as a civic-history landmark rather than a casual museum stop. Official and tourism sources frame it as the seat of Catalonia''s government, and viewing it from Plaça de Sant Jaume helps connect the Gothic Quarter''s ceremonial architecture with present-day Catalan political life.","hours":{"mon":"Exterior viewing; guided visits by schedule","tue":"Exterior viewing; guided visits by schedule","wed":"Exterior viewing; guided visits by schedule","thu":"Exterior viewing; guided visits by schedule","fri":"Exterior viewing; guided visits by schedule","sat":"Exterior viewing; guided visits by schedule","sun":"Exterior viewing; guided visits by schedule"}}],"sources":[{"name":"Barcelona Turisme - Gothic Quarter","url":"https://www.barcelonaturisme.com"},{"name":"MUHBA official","url":"https://www.barcelona.cat/museuhistoria/"},{"name":"Barcelona Cathedral official","url":"https://catedralbcn.org"},{"name":"Time Out - Barcelona things to do","url":"https://www.timeout.com/barcelona/things-to-do/best-things-to-do-in-barcelona"}]}'::jsonb),
  ('list-barcelona-el-born-culture', 'barcelona-el-born-culture', 'Culture', 'Spain', 'Barcelona', 'El Born', '{"id":"list-barcelona-el-born-culture","slug":"barcelona-el-born-culture","seoSlug":"best-museums-and-cultural-stops","seoTitle":"Best Museums and Cultural Stops in El Born, Barcelona","seoDescription":"Best museums and cultural stops in El Born, Barcelona, from the Picasso Museum and Santa Maria del Mar to medieval memory sites and Modernista music rooms.","title":"Picasso, Markets, and Memory","description":"El Born cultural stops connecting Picasso, medieval mercantile Barcelona, music, and the neighborhood''s dense museum-and-church circuit.","url":"https://www.google.com/maps/search/el+born+culture+barcelona","category":"Culture","location":{"city":"Barcelona","neighborhood":"El Born","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-culture","name":"R Culture","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-29T00:00:00.000Z","stops":[{"id":"born-picasso-museum","name":"Museu Picasso","coordinates":[41.3853,2.1815],"description":"Museu Picasso is El Born''s essential museum because official collection material and city guides emphasize Picasso''s formative Barcelona years. The five medieval palaces are part of the experience, and the strongest reason to go is the depth of early work, Blue Period context, and the Las Meninas series rather than a greatest-hits survey.","hours":{"mon":"Closed","tue":"9:00 AM-8:00 PM","wed":"9:00 AM-8:00 PM","thu":"9:00 AM-9:00 PM","fri":"9:00 AM-9:00 PM","sat":"9:00 AM-9:00 PM","sun":"9:00 AM-8:00 PM"}},{"id":"born-santa-maria-del-mar","name":"Basílica de Santa Maria del Mar","coordinates":[41.3839,2.1822],"description":"Santa Maria del Mar is included as the neighborhood-made Gothic counterpoint to Barcelona Cathedral. Tourism and heritage sources highlight its Ribera guild origins, clean Catalan Gothic proportions, and soaring stone interior, making it one of the best places to feel El Born''s medieval merchant history in architectural form.","hours":{"mon":"9:00 AM-8:00 PM","tue":"9:00 AM-8:00 PM","wed":"9:00 AM-8:00 PM","thu":"9:00 AM-8:00 PM","fri":"9:00 AM-8:00 PM","sat":"9:00 AM-8:00 PM","sun":"9:00 AM-8:00 PM"}},{"id":"born-ccm","name":"El Born Centre de Cultura i Memòria","coordinates":[41.3867,2.1833],"description":"El Born Centre de Cultura i Memòria is valuable because official sources position it as both a preserved market hall and an archaeological memory site. The exposed 1700s street remains make the consequences of 1714 and the transformation of the neighborhood easier to grasp than a standard museum panel would.","hours":{"mon":"Closed","tue":"10:00 AM-7:00 PM","wed":"10:00 AM-7:00 PM","thu":"10:00 AM-7:00 PM","fri":"10:00 AM-7:00 PM","sat":"10:00 AM-7:00 PM","sun":"10:00 AM-7:00 PM"}},{"id":"born-palau-musica","name":"Palau de la Música Catalana","coordinates":[41.3876,2.1753],"description":"Palau de la Música Catalana appears in El Born-adjacent culture lists because official and UNESCO-linked sources consistently treat it as one of Barcelona''s great Modernista interiors. The stained-glass skylight, ceramic columns, sculptural facade, and live-concert use make it worth seeing by tour or performance rather than only from the sidewalk.","hours":{"mon":"9:00 AM-9:00 PM","tue":"9:00 AM-9:00 PM","wed":"9:00 AM-9:00 PM","thu":"9:00 AM-9:00 PM","fri":"9:00 AM-9:00 PM","sat":"9:00 AM-9:00 PM","sun":"9:00 AM-3:30 PM"}},{"id":"born-moco-museum","name":"Moco Museum Barcelona","coordinates":[41.3852,2.181],"description":"Moco Museum is included as a contemporary counterweight to El Born''s heavy historic circuit. Its source profile is more visitor-demand and modern-art driven than civic-history driven, with street art, immersive work, and recognizable names making it useful for travelers who want a lighter museum after Picasso or Santa Maria del Mar.","hours":{"mon":"9:00 AM-8:00 PM","tue":"9:00 AM-8:00 PM","wed":"9:00 AM-8:00 PM","thu":"9:00 AM-8:00 PM","fri":"9:00 AM-8:00 PM","sat":"9:00 AM-8:00 PM","sun":"9:00 AM-8:00 PM"}}],"sources":[{"name":"Museu Picasso official","url":"https://museupicassobcn.cat"},{"name":"Palau de la Música Catalana official","url":"https://www.palaumusica.cat"},{"name":"El Born CCM official","url":"https://elbornculturaimemoria.barcelona.cat"},{"name":"Barcelona Turisme","url":"https://www.barcelonaturisme.com"}]}'::jsonb),
  ('list-barcelona-eixample-culture', 'barcelona-eixample-culture', 'Culture', 'Spain', 'Barcelona', 'Eixample', '{"id":"list-barcelona-eixample-culture","slug":"barcelona-eixample-culture","seoSlug":"best-museums-and-cultural-stops","seoTitle":"Best Museums and Cultural Stops in Eixample, Barcelona","seoDescription":"Best museums and cultural stops in Eixample, Barcelona, focused on Gaudi houses, Sagrada Familia, Modernista architecture, and design landmarks across the grid.","title":"Modernisme Power Walk","description":"Eixample architecture and design stops, from Gaudí''s major houses to Modernista institutions that define the grid.","url":"https://www.google.com/maps/search/eixample+culture+barcelona","category":"Culture","location":{"city":"Barcelona","neighborhood":"Eixample","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-culture","name":"R Culture","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-29T00:00:00.000Z","stops":[{"id":"eixample-sagrada-familia","name":"Sagrada Família","coordinates":[41.4036,2.1744],"description":"Sagrada Família is the Eixample landmark every source converges on: official material, UNESCO context, and visitor guides all frame it as Gaudí''s unfinished masterwork. The reason to list it is the interior experience as much as the facade: branching columns, colored glass, symbolic towers, and the visible story of construction still unfolding.","hours":{"mon":"9:00 AM-8:00 PM","tue":"9:00 AM-8:00 PM","wed":"9:00 AM-8:00 PM","thu":"9:00 AM-8:00 PM","fri":"9:00 AM-8:00 PM","sat":"9:00 AM-8:00 PM","sun":"9:00 AM-8:00 PM"}},{"id":"eixample-casa-batllo","name":"Casa Batlló","coordinates":[41.3917,2.1649],"description":"Casa Batlló is included because official and guide sources treat it as one of the clearest examples of Gaudí turning a private house into a total artwork. The roofline, tiled facade, bone-like structure, light well, and immersive interpretation make it more than a photo stop on Passeig de Gràcia.","hours":{"mon":"9:00 AM-10:00 PM","tue":"9:00 AM-10:00 PM","wed":"9:00 AM-10:00 PM","thu":"9:00 AM-10:00 PM","fri":"9:00 AM-10:00 PM","sat":"9:00 AM-10:00 PM","sun":"9:00 AM-10:00 PM"}},{"id":"eixample-la-pedrera","name":"Casa Milà / La Pedrera","coordinates":[41.3954,2.1619],"description":"Casa Milà / La Pedrera belongs as the broader domestic-architecture lesson in Eixample. Official sources emphasize the undulating stone facade, attic structure, apartment design, and rooftop chimneys, so it works well for travelers who want to understand how Gaudí translated movement and natural forms into an inhabited building.","hours":{"mon":"9:00 AM-8:00 PM","tue":"9:00 AM-8:00 PM","wed":"9:00 AM-8:00 PM","thu":"9:00 AM-8:00 PM","fri":"9:00 AM-8:00 PM","sat":"9:00 AM-8:00 PM","sun":"9:00 AM-8:00 PM"}},{"id":"eixample-fundacio-tapies","name":"Fundació Antoni Tàpies","coordinates":[41.391,2.163],"description":"Fundació Antoni Tàpies is included because it combines a major Catalan artist with a Modernista industrial building, giving Eixample culture a modern-art layer beyond Gaudí. Source material highlights Tàpies'' textured, material-heavy work and the building''s distinctive rooftop sculpture, making it a focused stop for art-minded visitors.","hours":{"mon":"Closed","tue":"10:00 AM-7:00 PM","wed":"10:00 AM-7:00 PM","thu":"10:00 AM-7:00 PM","fri":"10:00 AM-7:00 PM","sat":"10:00 AM-7:00 PM","sun":"10:00 AM-7:00 PM"}},{"id":"eixample-casa-amatller","name":"Casa Amatller","coordinates":[41.3915,2.165],"description":"Casa Amatller is a useful corrective to Gaudí-only Eixample itineraries. Official and tourism sources position Puig i Cadafalch''s house as a key part of the Block of Discord, with stepped gables, decorative craft, and chocolate-family history that help explain the competitive Modernista energy of Passeig de Gràcia.","hours":{"mon":"10:00 AM-7:00 PM","tue":"10:00 AM-7:00 PM","wed":"10:00 AM-7:00 PM","thu":"10:00 AM-7:00 PM","fri":"10:00 AM-7:00 PM","sat":"10:00 AM-7:00 PM","sun":"10:00 AM-7:00 PM"}}],"sources":[{"name":"Sagrada Família official","url":"https://sagradafamilia.org"},{"name":"Casa Batlló official","url":"https://www.casabatllo.es"},{"name":"La Pedrera official","url":"https://www.lapedrera.com"},{"name":"UNESCO - Works of Antoni Gaudí","url":"https://whc.unesco.org/en/list/320"}]}'::jsonb),
  ('list-barcelona-gracia-culture', 'barcelona-gracia-culture', 'Culture', 'Spain', 'Barcelona', 'Gràcia', '{"id":"list-barcelona-gracia-culture","slug":"barcelona-gracia-culture","seoSlug":"best-museums-and-cultural-stops","seoTitle":"Best Museums and Cultural Stops in Gràcia, Barcelona","seoDescription":"Best museums and cultural stops in Gràcia, Barcelona, balancing Park Guell and Casa Vicens with plazas, cinemas, markets, and neighborhood public life.","title":"Gaudí Beginnings and Plaza Life","description":"Gràcia culture stops that balance Gaudí tourism with the neighborhood''s plazas, cinemas, markets, and village-scale public life.","url":"https://www.google.com/maps/search/gracia+culture+barcelona","category":"Culture","location":{"city":"Barcelona","neighborhood":"Gràcia","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-culture","name":"R Culture","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-29T00:00:00.000Z","stops":[{"id":"gracia-park-guell-culture","name":"Park Güell","coordinates":[41.4145,2.1527],"description":"Park Güell is listed through both official and UNESCO context because it turns Gràcia''s hillside into Gaudí''s large-scale urban experiment. The mosaic terrace, viaducts, gatehouses, serpentine bench, and city views make it a cultural stop, not just a park, especially when paired with the neighborhood below.","hours":{"mon":"9:30 AM-7:30 PM","tue":"9:30 AM-7:30 PM","wed":"9:30 AM-7:30 PM","thu":"9:30 AM-7:30 PM","fri":"9:30 AM-7:30 PM","sat":"9:30 AM-7:30 PM","sun":"9:30 AM-7:30 PM"}},{"id":"gracia-casa-vicens","name":"Casa Vicens","coordinates":[41.4035,2.1507],"description":"Casa Vicens is included because official sources identify it as Gaudí''s first major house and an early statement of his style. Its ceramic surfaces, botanical motifs, Islamic-influenced geometry, and domestic scale make it one of the best ways to see Gaudí before the later, more monumental works.","hours":{"mon":"9:00 AM-8:00 PM","tue":"9:00 AM-8:00 PM","wed":"9:00 AM-8:00 PM","thu":"9:00 AM-8:00 PM","fri":"9:00 AM-8:00 PM","sat":"9:00 AM-8:00 PM","sun":"9:00 AM-8:00 PM"}},{"id":"gracia-cines-verdi","name":"Cines Verdi","coordinates":[41.4033,2.1564],"description":"Cines Verdi represents Gràcia''s everyday cultural life rather than a monument. Local guides and neighborhood knowledge support it as a long-running original-language cinema, useful for festival programming, independent films, and understanding why Gràcia still feels like a lived-in village instead of only a sightseeing zone.","hours":{"mon":"Showtimes vary","tue":"Showtimes vary","wed":"Showtimes vary","thu":"Showtimes vary","fri":"Showtimes vary","sat":"Showtimes vary","sun":"Showtimes vary"}},{"id":"gracia-placa-del-sol","name":"Plaça del Sol","coordinates":[41.401,2.1574],"description":"Plaça del Sol is included because guide sources consistently describe Gràcia through its plazas, and this is the neighborhood''s clearest social stage. The value is observational: terraces, evening gatherings, musicians, and local routines that explain the district''s village identity better than a formal attraction would.","hours":{"mon":"Open public space","tue":"Open public space","wed":"Open public space","thu":"Open public space","fri":"Open public space","sat":"Open public space","sun":"Open public space"}},{"id":"gracia-mercat-llibertat","name":"Mercat de la Llibertat","coordinates":[41.4002,2.1532],"description":"Mercat de la Llibertat gives the Gràcia list a daily-life anchor. City and tourism sources frame it as a restored 19th-century market hall, and it is best used for morning food culture, neighborhood pacing, and a quieter look at local shopping before the evening plaza scene takes over.","hours":{"mon":"8:00 AM-2:00 PM","tue":"8:00 AM-8:00 PM","wed":"8:00 AM-2:00 PM","thu":"8:00 AM-8:00 PM","fri":"8:00 AM-8:00 PM","sat":"8:00 AM-3:00 PM","sun":"Closed"}}],"sources":[{"name":"Park Güell official","url":"https://parkguell.barcelona"},{"name":"Casa Vicens official","url":"https://casavicens.org"},{"name":"Time Out - Gràcia guide","url":"https://www.timeout.com/barcelona/things-to-do/gracia"},{"name":"Barcelona Turisme","url":"https://www.barcelonaturisme.com"}]}'::jsonb),
  ('list-barcelona-poble-sec-culture', 'barcelona-poble-sec-culture', 'Culture', 'Spain', 'Barcelona', 'Poble-sec', '{"id":"list-barcelona-poble-sec-culture","slug":"barcelona-poble-sec-culture","seoSlug":"best-museums-and-cultural-stops","seoTitle":"Best Museums and Cultural Stops in Poble-sec, Barcelona","seoDescription":"Best museums and cultural stops in Poble-sec and Montjuic, Barcelona, including MNAC, Fundacio Joan Miro, CaixaForum, hilltop history, and performance spaces.","title":"Montjuïc Museum Day","description":"Poble-sec and Montjuïc culture stops for museums, performance spaces, hilltop history, and the city''s strongest art-and-view cluster.","url":"https://www.google.com/maps/search/poble+sec+montjuic+culture+barcelona","category":"Culture","location":{"city":"Barcelona","neighborhood":"Poble-sec","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-culture","name":"R Culture","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-29T00:00:00.000Z","stops":[{"id":"poblesec-mnac","name":"MNAC","coordinates":[41.3688,2.1536],"description":"MNAC is the Montjuïc heavyweight because official museum sources place major Catalan art history inside the Palau Nacional. Its Romanesque frescoes, Gothic work, modernisme, photography, and terrace views make it the strongest single museum stop for understanding Catalonia''s visual culture at scale.","hours":{"mon":"Closed","tue":"10:00 AM-8:00 PM","wed":"10:00 AM-8:00 PM","thu":"10:00 AM-8:00 PM","fri":"10:00 AM-8:00 PM","sat":"10:00 AM-8:00 PM","sun":"10:00 AM-3:00 PM"}},{"id":"poblesec-fundacio-joan-miro","name":"Fundació Joan Miró","coordinates":[41.3686,2.1592],"description":"Fundació Joan Miró is included because official sources and guide coverage agree on the strength of both the collection and the building. The Sert-designed museum, sculpture terraces, works on paper, and Miró''s color language make it a calmer, more focused Montjuïc alternative to MNAC''s encyclopedic scale.","hours":{"mon":"Closed","tue":"10:00 AM-7:00 PM","wed":"10:00 AM-7:00 PM","thu":"10:00 AM-7:00 PM","fri":"10:00 AM-7:00 PM","sat":"10:00 AM-7:00 PM","sun":"10:00 AM-7:00 PM"}},{"id":"poblesec-caixaforum","name":"CaixaForum Barcelona","coordinates":[41.3717,2.1491],"description":"CaixaForum Barcelona earns its place as a flexible exhibition stop in a converted Modernista textile factory. Source material highlights the industrial architecture and rotating programming, so it is useful when travelers want a shorter culture visit near Plaça d''Espanya without committing to a large permanent collection.","hours":{"mon":"10:00 AM-7:00 PM","tue":"10:00 AM-7:00 PM","wed":"10:00 AM-7:00 PM","thu":"10:00 AM-7:00 PM","fri":"10:00 AM-7:00 PM","sat":"10:00 AM-7:00 PM","sun":"10:00 AM-7:00 PM"}},{"id":"poblesec-montjuic-castle","name":"Montjuïc Castle","coordinates":[41.3634,2.1661],"description":"Montjuïc Castle is included for its layered military and civic history as much as its views. Tourism sources connect it to the hill''s defensive role, port control, and later political memory, making it a strong endpoint for a cable-car route, garden walk, or broader Montjuïc history day.","hours":{"mon":"9:00 AM-8:00 PM","tue":"9:00 AM-8:00 PM","wed":"9:00 AM-8:00 PM","thu":"9:00 AM-8:00 PM","fri":"9:00 AM-8:00 PM","sat":"9:00 AM-8:00 PM","sun":"9:00 AM-8:00 PM"}},{"id":"poblesec-poble-espanyol","name":"Poble Espanyol","coordinates":[41.3687,2.1475],"description":"Poble Espanyol is a 1929 exhibition-era site that sources frame as an open-air survey of Spanish regional architecture and craft. It is not a normal village, and that is the point: the value is workshops, event programming, plazas, and a compact, staged look at architectural styles from across Spain.","hours":{"mon":"9:00 AM-8:00 PM","tue":"9:00 AM-8:00 PM","wed":"9:00 AM-8:00 PM","thu":"9:00 AM-8:00 PM","fri":"9:00 AM-8:00 PM","sat":"9:00 AM-8:00 PM","sun":"9:00 AM-8:00 PM"}},{"id":"poblesec-teatre-grec","name":"Teatre Grec","coordinates":[41.3704,2.1598],"description":"Teatre Grec belongs because it ties Poble-sec/Montjuïc to performance culture and summer festival life. Built into a former quarry, it is most meaningful during programmed events, but the amphitheater and gardens also make sense as part of a daytime walk through the hill''s cultural landscape.","hours":{"mon":"Open public gardens; performances by schedule","tue":"Open public gardens; performances by schedule","wed":"Open public gardens; performances by schedule","thu":"Open public gardens; performances by schedule","fri":"Open public gardens; performances by schedule","sat":"Open public gardens; performances by schedule","sun":"Open public gardens; performances by schedule"}}],"sources":[{"name":"MNAC official","url":"https://www.museunacional.cat"},{"name":"Fundació Joan Miró official","url":"https://www.fmirobcn.org"},{"name":"CaixaForum Barcelona","url":"https://caixaforum.org"},{"name":"Barcelona Turisme - Montjuïc","url":"https://www.barcelonaturisme.com"}]}'::jsonb),
  ('list-barcelona-gothic-quarter-stays', 'barcelona-gothic-quarter-stays', 'Stay', 'Spain', 'Barcelona', 'Gothic Quarter', '{"id":"list-barcelona-gothic-quarter-stays","slug":"barcelona-gothic-quarter-stays","seoSlug":"best-places-to-stay","seoTitle":"Best Places to Stay in the Gothic Quarter, Barcelona","seoDescription":"Best places to stay in the Gothic Quarter, Barcelona, for old-city hotels, boutique stays, hostels, cathedral access, and walkable historic lanes.","title":"Sleep in the Old City","description":"Gothic Quarter stays for travelers who want old-city texture, walkability, and immediate access to cathedral lanes without relying on taxis.","url":"https://www.google.com/maps/search/gothic+quarter+hotels+hostels+barcelona","category":"Stay","location":{"city":"Barcelona","neighborhood":"Gothic Quarter","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-stay","name":"R Stay","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-29T00:00:00.000Z","stops":[{"id":"gothic-hotel-neri","name":"Hotel Neri","coordinates":[41.3833,2.1754],"description":"Hotel Neri is the Gothic Quarter stay for travelers who want historic texture without giving up boutique comfort. Hotel-guide and map signals support it for its restored palace setting beside Sant Felip Neri, quiet rooms, and intimate scale, making it better for a romantic old-city base than for resort-style amenities.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"gothic-mercer-hotel","name":"Mercer Hotel Barcelona","coordinates":[41.3826,2.1784],"description":"Mercer Hotel Barcelona is included as the luxury heritage stay in the Gothic core. Source coverage repeatedly points to the Roman wall fragments, medieval fabric, courtyard calm, and high-service positioning, so it is best for travelers who want the old city built into the property itself.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"gothic-kimpton-vividora","name":"Kimpton Vividora Hotel","coordinates":[41.3843,2.1741],"description":"Kimpton Vividora is the polished lifestyle-hotel option near the cathedral, backed by hotel guides and Google Travel demand. Its value is central logistics, design-forward rooms, rooftop views, and a more contemporary service model for visitors who want the Gothic Quarter without staying in a small historic inn.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"gothic-h10-madison","name":"H10 Madison","coordinates":[41.386,2.176],"description":"H10 Madison is included because hotel sources and map demand show it as a practical central stay with a strong rooftop setup. It works well for first-time visitors who want cathedral access, Palau de la Música proximity, Plaça Catalunya transit, and a hotel that is straightforward rather than overly precious.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"gothic-safestay-gothic","name":"Safestay Barcelona Gothic","coordinates":[41.3838,2.1786],"description":"Safestay Barcelona Gothic gives the old-city list a budget option supported by location and hostel-platform visibility. The reason to choose it is not luxury; it is dorm pricing, social travel, and a base that sits between Gothic lanes, El Born, and the museum/bar circuit.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}}],"sources":[{"name":"Time Out - Best hotels in Barcelona","url":"https://www.timeout.com/barcelona/hotels/best-hotels-in-barcelona"},{"name":"Conde Nast Traveler - Barcelona hotels","url":"https://www.cntraveler.com/gallery/best-hotels-in-barcelona"},{"name":"Google Travel","url":"https://www.google.com/travel/hotels"}]}'::jsonb),
  ('list-barcelona-el-born-stays', 'barcelona-el-born-stays', 'Stay', 'Spain', 'Barcelona', 'El Born', '{"id":"list-barcelona-el-born-stays","slug":"barcelona-el-born-stays","seoSlug":"best-places-to-stay","seoTitle":"Best Places to Stay in El Born, Barcelona","seoDescription":"Best places to stay in El Born, Barcelona, including boutique hotels, practical hostals, museum-street bases, Ciutadella access, and lively old-town lodging.","title":"Boutique Beds by the Market","description":"El Born stays for travelers who want boutiques, museum streets, Ciutadella access, and a livelier old-town feel than the cathedral core.","url":"https://www.google.com/maps/search/el+born+hotels+hostels+barcelona","category":"Stay","location":{"city":"Barcelona","neighborhood":"El Born","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-stay","name":"R Stay","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-29T00:00:00.000Z","stops":[{"id":"born-barcelona-edition","name":"The Barcelona EDITION","coordinates":[41.3869,2.1763],"description":"The Barcelona EDITION is El Born''s strongest luxury stay because hotel guides and Google Travel signals consistently point to its Santa Caterina Market location, rooftop scene, restaurants, and high-design service. It suits travelers who want old-town energy but prefer a five-star, contemporary hotel ecosystem.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"born-kk-picasso","name":"K+K Hotel Picasso","coordinates":[41.3867,2.1852],"description":"K+K Hotel Picasso is included as a practical edge-of-Born hotel with park and museum access. Source signals support it for the rooftop pool, quieter location near Parc de la Ciutadella, and easy walks to the Picasso Museum, Estació de França, and Born restaurants.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"born-park-hotel","name":"Park Hotel Barcelona","coordinates":[41.3847,2.1855],"description":"Park Hotel Barcelona is a logistics-first Born stay: guides and map data support it for Estació de França, waterfront walks, and quick access into El Born. It is best for travelers who value transit and neighborhood dining over a high-design hotel experience.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"born-chic-basic","name":"chic&basic Born Boutique Hotel","coordinates":[41.386,2.1838],"description":"chic&basic Born Boutique Hotel is included because it matches the neighborhood''s design-shop personality better than a generic chain stay. Its 19th-century building, playful interiors, and central Born location make it useful for travelers who want style and walkability at a more moderate level than the EDITION.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"born-hostal-orleans","name":"Hostal Orleans","coordinates":[41.3845,2.1863],"description":"Hostal Orleans keeps the El Born list honest for budget travelers. Its source value is location and simplicity: near the station, park, waterfront, and Born museums, with basic rooms that make sense when the priority is spending the trip budget on food, culture, and nightlife.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}}],"sources":[{"name":"Time Out - Best hotels in Barcelona","url":"https://www.timeout.com/barcelona/hotels/best-hotels-in-barcelona"},{"name":"Conde Nast Traveler - Barcelona hotels","url":"https://www.cntraveler.com/gallery/best-hotels-in-barcelona"},{"name":"Google Travel","url":"https://www.google.com/travel/hotels"}]}'::jsonb),
  ('list-barcelona-eixample-stays', 'barcelona-eixample-stays', 'Stay', 'Spain', 'Barcelona', 'Eixample', '{"id":"list-barcelona-eixample-stays","slug":"barcelona-eixample-stays","seoSlug":"best-places-to-stay","seoTitle":"Best Places to Stay in Eixample, Barcelona","seoDescription":"Best places to stay in Eixample, Barcelona, for design hotels, central transit, Modernista architecture, hostels, and calmer bases outside the old-city lanes.","title":"Design Hotels on the Grid","description":"Eixample stays for design hotels, central transit, Modernista architecture, and a calmer base than the tight old-city lanes.","url":"https://www.google.com/maps/search/eixample+hotels+hostels+barcelona","category":"Stay","location":{"city":"Barcelona","neighborhood":"Eixample","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-stay","name":"R Stay","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-29T00:00:00.000Z","stops":[{"id":"eixample-casa-bonay-hotel","name":"Casa Bonay","coordinates":[41.3918,2.1746],"description":"Casa Bonay is the Eixample design-hotel anchor because travel guides and restaurant sources connect the rooms to a broader local ecosystem of coffee, natural wine, rooftop space, and dining. It works for travelers who want neighborhood life inside the hotel rather than a purely corporate base.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"eixample-almanac","name":"Almanac Barcelona","coordinates":[41.3906,2.1683],"description":"Almanac Barcelona is included as a polished luxury option near Passeig de Gràcia, supported by hotel-guide coverage and Google Travel demand. The draw is central positioning, contemporary rooms, rooftop views, and easy access to Eixample architecture without the density of the old city.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"eixample-praktik-bakery","name":"Praktik Bakery","coordinates":[41.3952,2.1639],"description":"Praktik Bakery is useful because hotel sources consistently remember the concept: a boutique stay built around an actual bakery. It is a mid-range Eixample pick for travelers who care about morning routine, smell-of-bread atmosphere, and walkability more than big-lobby luxury.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"eixample-the-one","name":"The One Barcelona","coordinates":[41.3958,2.1624],"description":"The One Barcelona is the higher-end Eixample stay near La Pedrera, chosen for rooftop pool appeal, quiet luxury positioning, and proximity to Passeig de Gràcia. It is a good fit when the traveler wants architectural sightseeing access with a calmer hotel feel than the Gothic Quarter.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"eixample-yeah-hostel","name":"Yeah Barcelona Hostel","coordinates":[41.3983,2.1654],"description":"Yeah Barcelona Hostel is included because it gives Eixample a social, budget-conscious option with dorms and private rooms. Its location works especially well for travelers splitting time between Gràcia, Sagrada Família, and Eixample dining, while still wanting hostel programming and shared spaces.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}}],"sources":[{"name":"Time Out - Best hotels in Barcelona","url":"https://www.timeout.com/barcelona/hotels/best-hotels-in-barcelona"},{"name":"The Infatuation - Barcelona hotels/restaurants guide","url":"https://www.theinfatuation.com/barcelona/guides/best-restaurants-hotels-barcelona"},{"name":"Google Travel","url":"https://www.google.com/travel/hotels"}]}'::jsonb),
  ('list-barcelona-gracia-stays', 'barcelona-gracia-stays', 'Stay', 'Spain', 'Barcelona', 'Gràcia', '{"id":"list-barcelona-gracia-stays","slug":"barcelona-gracia-stays","seoSlug":"best-places-to-stay","seoTitle":"Best Places to Stay in Gràcia, Barcelona","seoDescription":"Best places to stay in Gràcia, Barcelona, for village-like plazas, Park Guell access, budget hostels, boutique lodging, and a less tourist-saturated base.","title":"Village-Base Stays","description":"Gràcia stays for travelers who want village-like plazas, better local dining access, and a less tourist-saturated base above Diagonal.","url":"https://www.google.com/maps/search/gracia+hotels+hostels+barcelona","category":"Stay","location":{"city":"Barcelona","neighborhood":"Gràcia","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-stay","name":"R Stay","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-29T00:00:00.000Z","stops":[{"id":"gracia-casa-gracia","name":"Casa Gràcia","coordinates":[41.3978,2.1578],"description":"Casa Gràcia is the most flexible Gràcia stay because sources position it between hostel, hotel, and social hub. On the Diagonal edge, it works for private rooms, dorms, communal spaces, and travelers who want immediate access to Gràcia plazas without losing Eixample transit connections.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"gracia-sonder-la-casa-del-sol","name":"Sonder La Casa del Sol","coordinates":[41.4009,2.1576],"description":"Sonder La Casa del Sol is included for its exact neighborhood fit: compact boutique lodging right by Plaça del Sol. It suits travelers who want to step directly into Gràcia''s terrace culture, accept a smaller property format, and use the neighborhood itself as the main amenity.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"gracia-hotel-ronda-lesseps","name":"Hotel Ronda Lesseps","coordinates":[41.4069,2.1495],"description":"Hotel Ronda Lesseps is a practical northern Gràcia base, supported by map and hotel-platform signals for value, metro access, and proximity to Park Güell. It is best for travelers who prefer quieter nights and do not need to sleep in the most central plaza zone.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"gracia-rocket-hostels","name":"Rocket Hostels Gràcia","coordinates":[41.4108,2.1514],"description":"Rocket Hostels Gràcia earns a place as the low-cost hillside option near Park Güell. The fit is specific: backpackers or budget travelers who want a smaller hostel, less old-town noise, and easier access to the upper Gràcia/Collserola side of the city.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"gracia-catalonia-park-guell","name":"Catalonia Park Güell","coordinates":[41.4115,2.1459],"description":"Catalonia Park Güell is a value hotel for travelers using Gràcia as a quieter northern base. Source signals point to practical rooms, pool/value appeal, and metro reach, so it belongs for guests prioritizing price and Park Güell access over boutique-neighborhood charm.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}}],"sources":[{"name":"Time Out - Barcelona hotels","url":"https://www.timeout.com/barcelona/hotels"},{"name":"Google Travel","url":"https://www.google.com/travel/hotels"},{"name":"Barcelona Turisme accommodation directory","url":"https://www.barcelonaturisme.com"}]}'::jsonb),
  ('list-barcelona-poble-sec-stays', 'barcelona-poble-sec-stays', 'Stay', 'Spain', 'Barcelona', 'Poble-sec', '{"id":"list-barcelona-poble-sec-stays","slug":"barcelona-poble-sec-stays","seoSlug":"best-places-to-stay","seoTitle":"Best Places to Stay in Poble-sec, Barcelona","seoDescription":"Best places to stay in Poble-sec, Barcelona, for Montjuic access, theater nights, Sala Apolo proximity, budget rooms, and a base between old town and the hill.","title":"Sleep Near Montjuïc","description":"Poble-sec stays for Montjuïc access, theater nights, Apolo proximity, and a useful base between old town and the hill.","url":"https://www.google.com/maps/search/poble+sec+hotels+hostels+barcelona","category":"Stay","location":{"city":"Barcelona","neighborhood":"Poble-sec","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-stay","name":"R Stay","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-29T00:00:00.000Z","stops":[{"id":"poblesec-hotel-brummell","name":"Hotel Brummell","coordinates":[41.3713,2.166],"description":"Hotel Brummell is Poble-sec''s design-led stay, supported by hotel-guide attention for its calm local setting near Montjuïc, small scale, and stylish common spaces. It is the best fit when travelers want the neighborhood''s food and theater access without staying in a large Paral·lel hotel.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"poblesec-innside-apolo","name":"INNSiDE by Meliá Barcelona Apolo","coordinates":[41.3749,2.1701],"description":"INNSiDE by Meliá Barcelona Apolo is the practical large-hotel choice by Paral·lel and Sala Apolo. Source and map signals support it for nightlife access, metro convenience, conference-scale reliability, and easy walks toward the old town, port, and Poble-sec tapas streets.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"poblesec-hostal-apolo","name":"Hostal Apolo","coordinates":[41.3747,2.169],"description":"Hostal Apolo is included as a simple budget base in the theater-and-club corridor. The value is location rather than amenities: quick access to Paral·lel, Sala Apolo, Carrer de Blai, and Montjuïc for travelers who need an affordable room more than a design stay.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"poblesec-coronado","name":"Hotel Coronado","coordinates":[41.3744,2.1669],"description":"Hotel Coronado is another no-frills Poble-sec option supported by map visibility and location utility. It works for short stays focused on tapas, shows, and transit, especially when the traveler wants to spend less on the room and stay close to Carrer de Blai.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"poblesec-hostal-bcn-port","name":"Hostal Bcn Port","coordinates":[41.3753,2.1758],"description":"Hostal Bcn Port is included for travelers whose Barcelona logistics involve the port side of Poble-sec. It is budget-friendly, simple, and useful for cruise-adjacent stays or Rambla-to-Montjuïc walking routes, with less neighborhood charm than Brummell but stronger practical positioning.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}}],"sources":[{"name":"Time Out - Barcelona hotels","url":"https://www.timeout.com/barcelona/hotels"},{"name":"Google Travel","url":"https://www.google.com/travel/hotels"},{"name":"Barcelona Turisme accommodation directory","url":"https://www.barcelonaturisme.com"}]}'::jsonb),
  ('list-barcelona-citywide-hostels', 'barcelona-best-hostels-citywide', 'Stay', 'Spain', 'Barcelona', null, '{"id":"list-barcelona-citywide-hostels","slug":"barcelona-best-hostels-citywide","seoSlug":"best-hostels","seoTitle":"Best Hostels in Barcelona","seoDescription":"Best hostels in Barcelona, pulling the strongest hostel pick from each neighborhood guide for social dorms, private rooms, location, and traveler fit.","title":"Barcelona Hostel Shortlist","description":"A citywide hostel shortlist built from the strongest hostel pick in each Barcelona neighborhood guide, balancing social energy, location, dorm quality, and practical transit.","url":"https://www.google.com/maps/search/best+hostels+barcelona","category":"Stay","location":{"city":"Barcelona","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-stay","name":"R Stay","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-29T00:00:00.000Z","stops":[{"id":"barcelona-hostel-shortlist-kabul","name":"Kabul Party Hostel Barcelona","coordinates":[41.3802,2.1758],"description":"Kabul is the citywide pick for travelers who want Barcelona''s hostel scene to double as the nightlife plan. Hostelworld, Google Maps, and long-running backpacker coverage consistently support it for Plaça Reial location, organized social programming, rooftop/common-space energy, and fast access to the Gothic Quarter bar circuit; it is a strong fit for outgoing solo travelers, not for light sleepers.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"barcelona-hostel-shortlist-360-borne","name":"360 Hostel Borne","coordinates":[41.3898,2.1805],"description":"360 Hostel Borne is the El Born/Arc de Triomf representative because it gives travelers a social base without placing the dorms directly on the loudest old-town streets. Hostel-platform and map signals point to shared meals, activities, kitchen/common-space usefulness, and easy walks to Ciutadella, El Born, and central transit.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"barcelona-hostel-shortlist-yeah","name":"Yeah Barcelona Hostel","coordinates":[41.3983,2.1654],"description":"Yeah Barcelona is the Eixample pick because it combines polished dorms, private rooms, and structured social programming in a location that works for Sagrada Familia, lower Gracia, and Eixample dining. Multiple hostel and map sources make it one of the safest all-around recommendations when travelers want social energy without sleeping in the Gothic core.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"barcelona-hostel-shortlist-casa-gracia","name":"Casa Gracia","coordinates":[41.3978,2.1578],"description":"Casa Gracia is the Gracia pick because it bridges hostel, hotel, and neighborhood social hub better than a pure dorm property. Source signals support it for dorm/private flexibility, Diagonal transit, communal programming, and immediate access to Gracia''s plaza-and-restaurant life, making it especially useful for travelers who want style and a less old-town-heavy base.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"barcelona-hostel-shortlist-onefam-paralelo","name":"Onefam Paralelo","coordinates":[41.374,2.1658],"description":"Onefam Paralelo is the Poble-sec pick for solo travelers who want staff-led activities and a built-in group dynamic near Carrer de Blai, Montjuic, and Sala Apolo. Hostelworld and map signals support it as a community-first stay rather than just a cheap bed, which makes it the strongest representative for the neighborhood.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}}],"sources":[{"name":"Hostelworld - Barcelona hostels","url":"https://www.hostelworld.com/st/hostels/europe/spain/barcelona/"},{"name":"Google Maps - Barcelona hostels","url":"https://www.google.com/maps/search/best+hostels+barcelona"},{"name":"Casa Gracia official","url":"https://www.casagraciabcn.com/"},{"name":"Onefam Hostels - Barcelona","url":"https://onefamhostels.com/"}]}'::jsonb),
  ('list-barcelona-gothic-quarter-hostels', 'barcelona-gothic-quarter-hostels', 'Stay', 'Spain', 'Barcelona', 'Gothic Quarter', '{"id":"list-barcelona-gothic-quarter-hostels","slug":"barcelona-gothic-quarter-hostels","seoSlug":"best-hostels","seoTitle":"Best Hostels in the Gothic Quarter, Barcelona","seoDescription":"Best hostels in the Gothic Quarter, Barcelona, including old-city party hostels, cathedral-area dorms, budget private rooms, and walkable bases near Placa Reial and El Born.","title":"Old-City Dorms and Party Bases","description":"Gothic Quarter hostel picks for travelers choosing between Plaça Reial party energy, cathedral-side calm, and simple old-city budget beds.","url":"https://www.google.com/maps/search/gothic+quarter+hostels+barcelona","category":"Stay","location":{"city":"Barcelona","neighborhood":"Gothic Quarter","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-stay","name":"R Stay","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-29T00:00:00.000Z","stops":[{"id":"gothic-hostel-kabul","name":"Kabul Party Hostel Barcelona","coordinates":[41.3802,2.1758],"description":"Kabul is the Gothic Quarter pick when the hostel itself is part of the nightlife plan. Hostelworld and long-running traveler coverage consistently frame it around Plaça Reial location, organized social programming, rooftop/common-space energy, and fast access to late bars; it is better for outgoing backpackers than for quiet sleepers.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"gothic-hostel-itaca","name":"Itaca Hostel","coordinates":[41.385,2.1749],"description":"Itaca is the calmer cathedral-area counterweight to Kabul: small-scale, central, and practical for travelers who want Gothic lanes, Plaça Catalunya, and old-city walking routes without committing to a party-hostel atmosphere. Hostelworld and review signals support it for location and simple dorm/private value.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"gothic-hostel-safestay-gothic","name":"Safestay Barcelona Gothic","coordinates":[41.3838,2.1786],"description":"Safestay Barcelona Gothic sits between the Gothic Quarter and El Born, making it useful for travelers who want budget beds close to Jaume I, the Picasso Museum, and cathedral lanes. It is a chain hostel rather than a boutique stay, but the value is location, scale, and predictable dorm infrastructure.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"gothic-hostel-new-york","name":"Hostel New York","coordinates":[41.381,2.1807],"description":"Hostel New York is the no-frills old-city option: basic, cheap, and positioned for travelers who care more about being near the port, Barceloneta, and Gothic nightlife than about design or a heavy social program. Use it as the budget fallback in this neighborhood set.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}}],"sources":[{"name":"Hostelworld - Barcelona hostels","url":"https://www.hostelworld.com/st/hostels/europe/spain/barcelona/"},{"name":"Hostelworld - Kabul Party Hostel Barcelona","url":"