  ('list-barcelona-el-born-hostels', 'barcelona-el-born-hostels', 'Stay', 'Spain', 'Barcelona', 'El Born', '{"id":"list-barcelona-el-born-hostels","slug":"barcelona-el-born-hostels","seoSlug":"best-hostels","seoTitle":"Best Hostels in El Born, Barcelona","seoDescription":"Best hostels in El Born, Barcelona, covering Arc de Triomf bases, social dorms, budget private rooms, and hostel stays close to Santa Maria del Mar, Ciutadella, and the Picasso Museum.","title":"Dorms by Ciutadella and the Born","description":"El Born hostel picks for travelers who want Ciutadella, Arc de Triomf, museum streets, and social dorm energy without sleeping deep in the busiest Gothic lanes.","url":"https://www.google.com/maps/search/el+born+hostels+barcelona","category":"Stay","location":{"city":"Barcelona","neighborhood":"El Born","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-stay","name":"R Stay","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-29T00:00:00.000Z","stops":[{"id":"born-hostel-360-borne","name":"360 Hostel Borne","coordinates":[41.3898,2.1805],"description":"360 Hostel Borne is the strongest El Born/Arc de Triomf hostel for travelers who want a social base without sleeping directly on the loudest old-town streets. Hostelworld and hostel-listing signals point to organized activities, communal kitchen/common space, and easy walks to Ciutadella, El Born, and central transit.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"born-hostel-born-barcelona","name":"Born Barcelona Hostel","coordinates":[41.3903,2.1811],"description":"Born Barcelona Hostel works as the quieter, smaller-format pick near Arc de Triomf and the upper edge of El Born. It suits travelers who want the neighborhood''s museum and park access but prefer a practical bed-and-base setup over a party-hostel identity.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"born-hostel-arc-house","name":"Arc House Barcelona","coordinates":[41.3908,2.1867],"description":"Arc House is included for budget travelers prioritizing Parc de la Ciutadella, Estacio del Nord, and fast walks into El Born. Source signals are more value-and-location driven than experience-led, so it belongs as a practical low-cost option rather than the most characterful stay.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"born-hostel-black-swan","name":"Black Swan Hostel","coordinates":[41.3907,2.1773],"description":"Black Swan sits just west of El Born near Arc de Triomf, but it earns a spot because hostel sources consistently highlight the social setup, tours, shared meals, and central transit reach. It is best for solo travelers who want an activity-forward hostel close to the Born without old-town noise at the door.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}}],"sources":[{"name":"Hostelworld - Barcelona hostels","url":"https://www.hostelworld.com/st/hostels/europe/spain/barcelona/"},{"name":"Google Maps - El Born hostels","url":"https://www.google.com/maps/search/el+born+hostels+barcelona"},{"name":"360 Hostel Borne official","url":"https://360hostelbcn.com/"}]}'::jsonb),
