  ('list-barcelona-citywide-dive-bars', 'barcelona-best-dive-bars-citywide', 'Nightlife', 'Spain', 'Barcelona', null, '{"id":"list-barcelona-citywide-dive-bars","slug":"barcelona-best-dive-bars-citywide","seoSlug":"best-dive-bars","seoTitle":"Best Dive Bars in Barcelona","seoDescription":"Best dive bars in Barcelona, pulling the strongest smaller bar picks from Eixample, El Born, the Gothic Quarter, Gràcia, and Poble-sec.","title":"Barcelona''s Best Low-Key Bars","description":"A citywide dive-bar rollup built from the strongest small, local, and character-heavy bar picks across each Barcelona neighborhood guide.","url":"https://www.google.com/maps/search/best+dive+bars+barcelona","category":"Nightlife","location":{"city":"Barcelona","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-nightlife","name":"R Nightlife","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-29T00:00:00.000Z","stops":[{"id":"citywide-dive-bar-marsella","name":"Bar Marsella","coordinates":[41.3852,2.1619],"description":"Bar Marsella is the Eixample/Raval-edge pick because it brings the strongest old-Barcelona dive-bar identity in the citywide set: absinthe history, worn-in rooms, late-night traffic, and enough grit to feel like a real counterpoint to polished cocktail Barcelona.","hours":{"mon":"6:00 PM-12:30 AM","tue":"6:00 PM-12:30 AM","wed":"6:00 PM-1:00 AM","thu":"6:00 PM-1:30 AM","fri":"6:00 PM-2:30 AM","sat":"6:00 PM-2:30 AM","sun":"6:00 PM-12:00 AM"}},{"id":"citywide-dive-el-xampanyet","name":"El Xampanyet","coordinates":[41.3847,2.1836],"description":"El Xampanyet is the El Born representative because it turns cava, anchovies, conservas, and packed counter service into a complete Barcelona bar ritual. It is tourist-famous now, but still earns the slot because the room''s pace, short-order food, and standing-room energy are exactly why the Born bar crawl works.","hours":{"mon":"7:00 PM-11:00 PM","tue":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","wed":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","thu":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","fri":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","sat":"12:00 PM-3:30 PM","sun":"Closed"}},{"id":"citywide-dive-la-plata","name":"Bar La Plata","coordinates":[41.3818,2.1799],"description":"Bar La Plata is the Gothic Quarter pick for travelers who want an old-city bar that does not need a concept. The draw is a short historic menu, house wine/vermouth rhythm, fast service, and a room that still feels specific rather than generic despite its central location.","hours":{"mon":"12:00 PM-12:30 AM","tue":"12:00 PM-12:30 AM","wed":"12:00 PM-12:30 AM","thu":"12:00 PM-1:30 AM","fri":"12:00 PM-2:00 AM","sat":"12:00 PM-2:00 AM","sun":"12:00 PM-12:00 AM"}},{"id":"citywide-dive-canigo","name":"Bar Canigó","coordinates":[41.4012,2.1609],"description":"Bar Canigó is the Gràcia pick because it captures the neighborhood''s regular-driven plaza culture better than a destination cocktail room would. It works for vermouth, casual beers, and observing the village-like evening rhythm that separates Gràcia from the old-city nightlife circuit.","hours":{"mon":"12:00 PM-11:00 PM","tue":"12:00 PM-11:00 PM","wed":"12:00 PM-11:00 PM","thu":"12:00 PM-11:30 PM","fri":"12:00 PM-12:00 AM","sat":"12:00 PM-12:00 AM","sun":"12:00 PM-10:30 PM"}},{"id":"citywide-dive-quimet-quimet","name":"Quimet & Quimet","coordinates":[41.3738,2.1635],"description":"Quimet & Quimet is the Poble-sec anchor because it is small, standing-only, and deeply tied to the neighborhood''s bottle-and-montadito culture. It is more famous than hidden, but the format is still pure Barcelona: quick pours, tight space, exceptional tins, and a crowd that turns food into bar energy.","hours":{"mon":"12:00 PM-11:00 PM","tue":"12:00 PM-11:00 PM","wed":"12:00 PM-11:00 PM","thu":"12:00 PM-11:30 PM","fri":"12:00 PM-12:00 AM","sat":"12:00 PM-12:00 AM","sun":"12:00 PM-10:30 PM"}}],"sources":[{"name":"Time Out - Best bars in Barcelona","url":"https://www.timeout.com/barcelona/bars-and-pubs/best-bars-in-barcelona"},{"name":"Time Out - El Born bars","url":"https://www.timeout.com/barcelona/bars-and-pubs/el-born-bars"},{"name":"Time Out - Gothic Quarter bars","url":"https://www.timeout.com/barcelona/bars-and-pubs/gothic-quarter-bars"},{"name":"Time Out - Gràcia bars","url":"https://www.timeout.com/barcelona/bars-and-pubs/gracia-bars"},{"name":"Time Out - Poble-sec bars","url":"https://www.timeout.com/barcelona/bars-and-pubs/poble-sec-bars"},{"name":"Google Maps","url":"https://maps.google.com"}]}'::jsonb),
  ('list-barcelona-citywide-popular-bars', 'barcelona-best-popular-bars-citywide', 'Nightlife', 'Spain', 'Barcelona', null, '{"id":"list-barcelona-citywide-popular-bars","slug":"barcelona-best-popular-bars-citywide","seoSlug":"best-bars","seoTitle":"Best Bars in Barcelona","seoDescription":"Best bars in Barcelona, aggregating the biggest destination cocktail rooms, live-music spots, and high-demand nightlife picks from each neighborhood guide.","title":"Barcelona Bars Worth Crossing Town For","description":"A citywide popular-bars guide built from the highest-demand nightlife picks across Barcelona''s neighborhood bar guides.","url":"https://www.google.com/maps/search/best+bars+barcelona","category":"Nightlife","location":{"city":"Barcelona","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-nightlife","name":"R Nightlife","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-29T00:00:00.000Z","stops":[{"id":"citywide-popular-dry-martini","name":"Dry Martini","coordinates":[41.3902,2.1552],"description":"Dry Martini is the classic-cocktail anchor for Barcelona: polished, historic, and useful when the night calls for proper service rather than novelty. It represents Eixample because the room''s old-school ritual and central location still give the city a serious martini house.","hours":{"mon":"1:00 PM-2:30 AM","tue":"1:00 PM-2:30 AM","wed":"1:00 PM-2:30 AM","thu":"1:00 PM-2:30 AM","fri":"1:00 PM-3:00 AM","sat":"1:00 PM-3:00 AM","sun":"4:30 PM-1:00 AM"}},{"id":"citywide-popular-paradiso","name":"Paradiso","coordinates":[41.3859,2.1822],"description":"Paradiso is the El Born pick because it is one of Barcelona''s clearest destination bars, with theatrical cocktails, international recognition, and queues that prove how much of the experience is spectacle. Use it when the point is a big-deal cocktail stop, not a casual neighborhood drink.","hours":{"mon":"6:00 PM-12:30 AM","tue":"6:00 PM-12:30 AM","wed":"6:00 PM-1:00 AM","thu":"6:00 PM-1:30 AM","fri":"6:00 PM-2:30 AM","sat":"6:00 PM-2:30 AM","sun":"6:00 PM-12:00 AM"}},{"id":"citywide-popular-jamboree","name":"Jamboree","coordinates":[41.3802,2.1757],"description":"Jamboree is the Gothic Quarter representative because it turns Plaça Reial into a late-night music anchor. It belongs in a citywide guide for travelers who want Barcelona nightlife to include live sets, club programming, and a room with institutional memory.","hours":{"mon":"10:00 PM-2:30 AM","tue":"10:00 PM-2:30 AM","wed":"10:00 PM-3:30 AM","thu":"10:00 PM-4:30 AM","fri":"10:00 PM-5:00 AM","sat":"10:00 PM-5:00 AM","sun":"10:00 PM-2:30 AM"}},{"id":"citywide-popular-heliogabal","name":"Heliogàbal","coordinates":[41.4029,2.1588],"description":"Heliogàbal is the Gràcia pick because it brings independent music and neighborhood bar culture together in a way that feels specific to the district. It is smaller than the big old-city venues, but the event pull and local music identity make it a real destination.","hours":{"mon":"6:00 PM-12:30 AM","tue":"6:00 PM-12:30 AM","wed":"6:00 PM-1:00 AM","thu":"6:00 PM-1:30 AM","fri":"6:00 PM-2:30 AM","sat":"6:00 PM-2:30 AM","sun":"6:00 PM-12:00 AM"}},{"id":"citywide-popular-apolo","name":"Sala Apolo","coordinates":[41.3752,2.1696],"description":"Sala Apolo is the Poble-sec pick and the city''s large-format nightlife anchor in this set. It works for club nights, concerts, and late plans that need more than a bar stool, especially when the evening is already moving along Paral·lel or Carrer de Blai.","hours":{"mon":"10:00 PM-2:30 AM","tue":"10:00 PM-2:30 AM","wed":"10:00 PM-3:30 AM","thu":"10:00 PM-4:30 AM","fri":"10:00 PM-5:00 AM","sat":"10:00 PM-5:00 AM","sun":"10:00 PM-2:30 AM"}}],"sources":[{"name":"Time Out - Best bars in Barcelona","url":"https://www.timeout.com/barcelona/bars-and-pubs/best-bars-in-barcelona"},{"name":"Time Out - El Born bars","url":"https://www.timeout.com/barcelona/bars-and-pubs/el-born-bars"},{"name":"Time Out - Gothic Quarter bars","url":"https://www.timeout.com/barcelona/bars-and-pubs/gothic-quarter-bars"},{"name":"Time Out - Gràcia bars","url":"https://www.timeout.com/barcelona/bars-and-pubs/gracia-bars"},{"name":"Time Out - Poble-sec bars","url":"https://www.timeout.com/barcelona/bars-and-pubs/poble-sec-bars"},{"name":"Google Maps","url":"https://maps.google.com"}]}'::jsonb),
  ('list-barcelona-citywide-culture', 'barcelona-best-culture-citywide', 'Culture', 'Spain', 'Barcelona', null, '{"id":"list-barcelona-citywide-culture","slug":"barcelona-best-culture-citywide","seoSlug":"best-culture","seoTitle":"Best Culture in Barcelona","seoDescription":"Best culture in Barcelona, aggregating the strongest museum, architecture, memory, and landmark picks from each neighborhood guide.","title":"Barcelona Culture Essentials","description":"A citywide culture rollup built from the strongest museum, architecture, memory, and landmark picks in each Barcelona neighborhood guide.","url":"https://www.google.com/maps/search/best+culture+barcelona","category":"Culture","location":{"city":"Barcelona","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-culture","name":"R Culture","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-29T00:00:00.000Z","stops":[{"id":"citywide-culture-barcelona-cathedral","name":"Barcelona Cathedral","coordinates":[41.3839,2.1762],"description":"Barcelona Cathedral is the Gothic Quarter''s clearest cultural anchor because it makes the old city legible: medieval street pattern, cloister, choir, rooftop views, and a surrounding square that explains how the neighborhood organizes itself around religious architecture.","hours":{"mon":"9:00 AM-8:00 PM","tue":"9:00 AM-8:00 PM","wed":"9:00 AM-8:00 PM","thu":"9:00 AM-8:00 PM","fri":"9:00 AM-8:00 PM","sat":"9:00 AM-8:00 PM","sun":"9:00 AM-8:00 PM"}},{"id":"citywide-culture-santa-maria-del-mar","name":"Basílica de Santa Maria del Mar","coordinates":[41.3839,2.1822],"description":"Santa Maria del Mar is the El Born representative because it tells the neighborhood''s merchant and guild story in stone. The cleaner Catalan Gothic interior contrasts with the cathedral and gives visitors a powerful cultural stop without needing a full museum-length visit.","hours":{"mon":"9:00 AM-8:00 PM","tue":"9:00 AM-8:00 PM","wed":"9:00 AM-8:00 PM","thu":"9:00 AM-8:00 PM","fri":"9:00 AM-8:00 PM","sat":"9:00 AM-8:00 PM","sun":"9:00 AM-8:00 PM"}},{"id":"citywide-culture-casa-batllo","name":"Casa Batlló","coordinates":[41.3917,2.1649],"description":"Casa Batlló is the Eixample pick because it concentrates Barcelona''s Modernista fantasy into one high-impact visit. It is tourist-heavy for good reason: facade, interiors, roofline, craft detail, and Passeig de Gràcia context make it one of the city''s most useful architecture stops.","hours":{"mon":"9:00 AM-8:00 PM","tue":"9:00 AM-8:00 PM","wed":"9:00 AM-8:00 PM","thu":"9:00 AM-8:00 PM","fri":"9:00 AM-8:00 PM","sat":"9:00 AM-8:00 PM","sun":"9:00 AM-8:00 PM"}},{"id":"citywide-culture-casa-vicens","name":"Casa Vicens","coordinates":[41.4035,2.1507],"description":"Casa Vicens is the Gràcia pick because it shows Gaudí before the monumental greatest-hits version. The domestic scale, ceramic surfaces, garden logic, and early stylistic experiments make it a more intimate architecture visit than the central icons.","hours":{"mon":"9:00 AM-8:00 PM","tue":"9:00 AM-8:00 PM","wed":"9:00 AM-8:00 PM","thu":"9:00 AM-8:00 PM","fri":"9:00 AM-8:00 PM","sat":"9:00 AM-8:00 PM","sun":"9:00 AM-8:00 PM"}},{"id":"citywide-culture-joan-miro","name":"Fundació Joan Miró","coordinates":[41.3686,2.1592],"description":"Fundació Joan Miró is the Poble-sec/Montjuïc pick because it combines a focused artist collection with a building and hillside setting that feel inseparable from the visit. It gives the citywide list a quieter art stop after the dense architecture of the center.","hours":{"mon":"Closed","tue":"10:00 AM-7:00 PM","wed":"10:00 AM-7:00 PM","thu":"10:00 AM-7:00 PM","fri":"10:00 AM-7:00 PM","sat":"10:00 AM-7:00 PM","sun":"10:00 AM-7:00 PM"}}],"sources":[{"name":"Barcelona Turisme","url":"https://www.barcelonaturisme.com"},{"name":"Casa Batlló official","url":"https://www.casabatllo.es"},{"name":"Casa Vicens official","url":"https://casavicens.org"},{"name":"Fundació Joan Miró official","url":"https://www.fmirobcn.org"},{"name":"Google Maps","url":"https://maps.google.com"}]}'::jsonb),
  ('list-barcelona-one-day-activities', 'barcelona-one-day-itinerary', 'Activities', 'Spain', 'Barcelona', null, '{"id":"list-barcelona-one-day-activities","slug":"barcelona-one-day-itinerary","seoSlug":"best-things-to-do","seoTitle":"Best Things to Do in Barcelona in One Day","seoDescription":"Best one-day Barcelona itinerary, combining one essential culture stop, one restaurant, one neighborhood walk, one low-key bar, and one destination nightlife option.","title":"One Strong Day in Barcelona","description":"A one-day city guide that samples the strongest categories without trying to see everything: architecture, lunch, neighborhood wandering, vermouth, and one big nightcap.","url":"https://www.google.com/maps/search/best+things+to+do+barcelona+one+day","category":"Activities","location":{"city":"Barcelona","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-activities","name":"R Activities","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-29T00:00:00.000Z","stops":[{"id":"barcelona-day-casa-batllo","name":"Casa Batlló","coordinates":[41.3917,2.1649],"description":"Start with the culture category at Casa Batlló because one day in Barcelona needs a high-impact Modernista anchor. It gives first-time visitors architecture, craft, rooftop drama, and Passeig de Gràcia context without sending them across the city before lunch.","hours":{"mon":"9:00 AM-8:00 PM","tue":"9:00 AM-8:00 PM","wed":"9:00 AM-8:00 PM","thu":"9:00 AM-8:00 PM","fri":"9:00 AM-8:00 PM","sat":"9:00 AM-8:00 PM","sun":"9:00 AM-8:00 PM"}},{"id":"barcelona-day-cal-pep","name":"Cal Pep","coordinates":[41.3835,2.1839],"description":"Use Cal Pep as the food stop because the counter format turns lunch into a Barcelona experience rather than just a meal. Seafood tapas, quick pacing, and Born location make it easy to transition from architecture into the old-city afternoon.","price":"$$$","priceSource":"The Infatuation / Google Maps","hours":{"mon":"Closed","tue":"1:00 PM-3:30 PM, 8:00 PM-11:00 PM","wed":"1:00 PM-3:30 PM, 8:00 PM-11:00 PM","thu":"1:00 PM-3:30 PM, 8:00 PM-11:00 PM","fri":"1:00 PM-3:30 PM, 8:00 PM-11:30 PM","sat":"1:00 PM-3:30 PM, 8:00 PM-11:30 PM","sun":"Closed"}},{"id":"barcelona-day-santa-maria","name":"Basílica de Santa Maria del Mar","coordinates":[41.3839,2.1822],"description":"Make Santa Maria del Mar the afternoon culture/walk stop: it is close to lunch, short enough for a one-day route, and gives the Born''s merchant history a clear architectural moment before the evening starts.","hours":{"mon":"9:00 AM-8:00 PM","tue":"9:00 AM-8:00 PM","wed":"9:00 AM-8:00 PM","thu":"9:00 AM-8:00 PM","fri":"9:00 AM-8:00 PM","sat":"9:00 AM-8:00 PM","sun":"9:00 AM-8:00 PM"}},{"id":"barcelona-day-xampanyet","name":"El Xampanyet","coordinates":[41.3847,2.1836],"description":"Move into the dive-bar category at El Xampanyet for cava, anchovies, and a packed counter that feels more Barcelona-specific than a generic aperitif. It is a short, loud, salty bridge between sightseeing and dinner-hour nightlife.","hours":{"mon":"7:00 PM-11:00 PM","tue":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","wed":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","thu":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","fri":"12:00 PM-3:30 PM, 7:00 PM-11:00 PM","sat":"12:00 PM-3:30 PM","sun":"Closed"}},{"id":"barcelona-day-paradiso","name":"Paradiso","coordinates":[41.3859,2.1822],"description":"End with the popular-bar category at Paradiso when the day calls for one memorable cocktail spectacle. The line can be part of the plan, so this works best as the final stop rather than a fragile mid-route reservation.","hours":{"mon":"6:00 PM-12:30 AM","tue":"6:00 PM-12:30 AM","wed":"6:00 PM-1:00 AM","thu":"6:00 PM-1:30 AM","fri":"6:00 PM-2:30 AM","sat":"6:00 PM-2:30 AM","sun":"6:00 PM-12:00 AM"}}],"sources":[{"name":"Barcelona Turisme","url":"https://www.barcelonaturisme.com"},{"name":"The Infatuation - Best Restaurants in Barcelona","url":"https://www.theinfatuation.com/barcelona/guides/best-restaurants-hotels-barcelona"},{"name":"Time Out - Best bars in Barcelona","url":"https://www.timeout.com/barcelona/bars-and-pubs/best-bars-in-barcelona"},{"name":"Google Maps","url":"https://maps.google.com"}]}'::jsonb),
  ('list-barcelona-weekend-activities', 'barcelona-weekend-itinerary', 'Activities', 'Spain', 'Barcelona', null, '{"id":"list-barcelona-weekend-activities","slug":"barcelona-weekend-itinerary","seoSlug":"best-things-to-do","seoTitle":"Best Things to Do in Barcelona for a Weekend","seoDescription":"Best Barcelona weekend itinerary, mixing culture, restaurants, dive bars, popular nightlife, hostel/stay context, and neighborhood pacing across two days.","title":"Barcelona Weekend Circuit","description":"A weekend guide that gives each category room to breathe: old-city culture, Eixample architecture, Montjuïc art, real meals, low-key bars, and one big night.","url":"https://www.google.com/maps/search/barcelona+weekend+itinerary","category":"Activities","location":{"city":"Barcelona","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-activities","name":"R Activities","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-29T00:00:00.000Z","stops":[{"id":"barcelona-weekend-casa-gracia","name":"Casa Gracia","coordinates":[41.3978,2.1578],"description":"Use Casa Gracia as the stay-category anchor for the weekend because it splits the difference between hostel social energy, private-room flexibility, and easy transit. Starting from Gràcia keeps the route from becoming only an old-city weekend.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"barcelona-weekend-casa-batllo","name":"Casa Batlló","coordinates":[41.3917,2.1649],"description":"Casa Batlló handles the headline culture slot on day one: it is central, visually immediate, and pairs naturally with an Eixample lunch or walk down Passeig de Gràcia.","hours":{"mon":"9:00 AM-8:00 PM","tue":"9:00 AM-8:00 PM","wed":"9:00 AM-8:00 PM","thu":"9:00 AM-8:00 PM","fri":"9:00 AM-8:00 PM","sat":"9:00 AM-8:00 PM","sun":"9:00 AM-8:00 PM"}},{"id":"barcelona-weekend-bodega-bonay","name":"Bodega Bonay","coordinates":[41.3918,2.1746],"description":"Bodega Bonay is the weekend food stop when the plan needs a stylish but manageable meal rather than a tasting-menu commitment. It keeps the route in Eixample while adding natural wine, anchovies, pastas, and a design-hotel setting.","price":"$$","priceSource":"The Infatuation / Resy","hours":{"mon":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","tue":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","wed":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","thu":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","fri":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sat":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sun":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM"}},{"id":"barcelona-weekend-bar-marsella","name":"Bar Marsella","coordinates":[41.3852,2.1619],"description":"Bar Marsella gives the weekend a dive-bar texture after the polished daytime stops. Its worn-in absinthe history and late-night feel work especially well before moving toward Gothic/Born nightlife.","hours":{"mon":"6:00 PM-12:30 AM","tue":"6:00 PM-12:30 AM","wed":"6:00 PM-1:00 AM","thu":"6:00 PM-1:30 AM","fri":"6:00 PM-2:30 AM","sat":"6:00 PM-2:30 AM","sun":"6:00 PM-12:00 AM"}},{"id":"barcelona-weekend-joan-miro","name":"Fundació Joan Miró","coordinates":[41.3686,2.1592],"description":"Fundació Joan Miró anchors day two with Montjuïc culture: a focused museum, hillside setting, and enough calm to reset after a late night without making the route feel empty.","hours":{"mon":"Closed","tue":"10:00 AM-7:00 PM","wed":"10:00 AM-7:00 PM","thu":"10:00 AM-7:00 PM","fri":"10:00 AM-7:00 PM","sat":"10:00 AM-7:00 PM","sun":"10:00 AM-7:00 PM"}},{"id":"barcelona-weekend-quimet-quimet","name":"Quimet & Quimet","coordinates":[41.3738,2.1635],"description":"Quimet & Quimet is the Poble-sec food-and-bar hybrid for the weekend route. Standing montaditos and bottles make it practical before Carrer de Blai or a club night while still feeling like a real Barcelona institution.","hours":{"mon":"12:00 PM-11:00 PM","tue":"12:00 PM-11:00 PM","wed":"12:00 PM-11:00 PM","thu":"12:00 PM-11:30 PM","fri":"12:00 PM-12:00 AM","sat":"12:00 PM-12:00 AM","sun":"12:00 PM-10:30 PM"}},{"id":"barcelona-weekend-apolo","name":"Sala Apolo","coordinates":[41.3752,2.1696],"description":"Sala Apolo is the popular-nightlife finish because weekends need at least one venue with citywide pull. Check the programming, then treat it as the big final stop rather than a casual bar-hop stop.","hours":{"mon":"10:00 PM-2:30 AM","tue":"10:00 PM-2:30 AM","wed":"10:00 PM-3:30 AM","thu":"10:00 PM-4:30 AM","fri":"10:00 PM-5:00 AM","sat":"10:00 PM-5:00 AM","sun":"10:00 PM-2:30 AM"}}],"sources":[{"name":"Barcelona Turisme","url":"https://www.barcelonaturisme.com"},{"name":"The Infatuation - Best Restaurants in Barcelona","url":"https://www.theinfatuation.com/barcelona/guides/best-restaurants-hotels-barcelona"},{"name":"Time Out - Best bars in Barcelona","url":"https://www.timeout.com/barcelona/bars-and-pubs/best-bars-in-barcelona"},{"name":"Fundació Joan Miró official","url":"https://www.fmirobcn.org"},{"name":"Google Maps","url":"https://maps.google.com"}]}'::jsonb),
  ('list-barcelona-week-activities', 'barcelona-week-itinerary', 'Activities', 'Spain', 'Barcelona', null, '{"id":"list-barcelona-week-activities","slug":"barcelona-week-itinerary","seoSlug":"best-things-to-do","seoTitle":"Best Things to Do in Barcelona for a Week","seoDescription":"Best one-week Barcelona itinerary, using the strongest citywide picks across restaurants, culture, dive bars, popular bars, hostels, stays, neighborhoods, and Montjuïc.","title":"A Full Week Across Barcelona","description":"A weeklong Barcelona guide that spreads the strongest category picks across neighborhoods, so the trip has architecture, food, bars, Montjuïc, Gràcia, hostels, and old-city texture.","url":"https://www.google.com/maps/search/barcelona+one+week+itinerary","category":"Activities","location":{"city":"Barcelona","country":"Spain","continent":"Europe","scope":"city"},"creator":{"id":"user-rguide-activities","name":"R Activities","avatar":"data:image/svg+xml;utf8,%0A%20%20%20%20%3Csvg%20xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22%20width%3D%22160%22%20height%3D%22160%22%20viewBox%3D%220%200%20160%20160%22%3E%0A%20%20%20%20%20%20%3Crect%20width%3D%22160%22%20height%3D%22160%22%20rx%3D%2280%22%20fill%3D%22%230f766e%22%20%2F%3E%0A%20%20%20%20%20%20%3Ctext%20x%3D%2250%25%22%20y%3D%2254%25%22%20text-anchor%3D%22middle%22%20dominant-baseline%3D%22middle%22%0A%20%20%20%20%20%20%20%20font-family%3D%22Arial%2C%20sans-serif%22%20font-size%3D%2276%22%20font-weight%3D%22700%22%20fill%3D%22white%22%3ER%3C%2Ftext%3E%0A%20%20%20%20%3C%2Fsvg%3E%0A%20%20"},"upvotes":0,"createdAt":"2026-04-29T00:00:00.000Z","stops":[{"id":"barcelona-week-yeah-hostel","name":"Yeah Barcelona Hostel","coordinates":[41.3983,2.1654],"description":"Use Yeah Barcelona as the hostel-category base for a week because the location works for Eixample, Gràcia, and Sagrada Familia while the social programming helps longer-stay travelers find plans without depending on random bar crawls.","hours":{"mon":"24 hours","tue":"24 hours","wed":"24 hours","thu":"24 hours","fri":"24 hours","sat":"24 hours","sun":"24 hours"}},{"id":"barcelona-week-casa-vicens","name":"Casa Vicens","coordinates":[41.4035,2.1507],"description":"Start the week in Gràcia with Casa Vicens so the architecture story begins before the giant Gaudí icons. It is smaller, more domestic, and gives the neighborhood''s village rhythm a cultural anchor.","hours":{"mon":"9:00 AM-8:00 PM","tue":"9:00 AM-8:00 PM","wed":"9:00 AM-8:00 PM","thu":"9:00 AM-8:00 PM","fri":"9:00 AM-8:00 PM","sat":"9:00 AM-8:00 PM","sun":"9:00 AM-8:00 PM"}},{"id":"barcelona-week-bemba","name":"Bemba Smash Burger","coordinates":[41.407,2.1583],"description":"Bemba fills the casual-food slot for a longer trip: quick, current, and useful when the week should include a cheap meal that is not another tapas fallback. It also keeps the first Gràcia day light.","price":"$","priceSource":"Eater / Instagram","hours":{"mon":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","tue":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","wed":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","thu":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM","fri":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sat":"12:30 PM-4:00 PM, 7:30 PM-11:30 PM","sun":"12:30 PM-4:00 PM, 7:30 PM-11:00 PM"}},{"id":"barcelona-week-casa-batllo","name":"Casa Batlló","coordinates":[41.3917,2.1649],"description":"Casa Batlló carries the major Eixample culture day with the strongest high-impact architecture stop in the central grid. Give it time rather than squeezing it into a rushed old-city morning.","hours":{"mon":"9:00 AM-8:00 PM","tue":"9:00 AM-8:00 PM","wed":"9:00 AM-8:00 PM","thu":"9:00 AM-8:00 PM","fri":"9:00 AM-8:00 PM","sat":"9:00 AM-8:00 PM","sun":"9:00 AM-8:00 PM"}},{"id":"barcelona-week-disfrutar","name":"Disfrutar","coordinates":[41.3878,2.1533],"description":"Disfrutar is the destination-restaurant slot for a full week because a longer itinerary can justify one trip-defining reservation. Keep it as the special meal, not a casual add-on, and build the day around the booking.","price":"$$$","priceSource":"MICHELIN Guide / World''s 50 Best","hours":{"mon":"Closed","tue":"1:00 PM-2:15 PM, 8:00 PM-9:15 PM","wed":"1:00 PM-2:15 PM, 8:00 PM-9:15 PM","thu":"1:00 PM-2:15 PM, 8:00 PM-9:15 PM","fri":"1:00 PM-2:15 PM, 8:00 PM-9:15 PM","sat":"1:00 PM-2:15 PM, 8:00 PM-9:15 PM","sun":"Closed"}},{"id":"barcelona-week-muhba","name":"MUHBA Plaça del Rei","coordinates":[41.3845,2.1777],"description":"MUHBA Plaça del Rei gives the old-city portion historical depth instead of letting the Gothic Quarter become only atmosphere. The underground Roman route and palace context make Barcelona''s layers easier to read for the rest of the week.","hours":{"mon":"Closed","tue":"10:00 AM-7:00 PM","wed":"10:00 AM-7:00 PM","thu":"10:00 AM-7:00 PM","fri":"10:00 AM-7:00 PM","sat":"10:00 AM-7:00 PM","sun":"10:00 AM-7:00 PM"}},{"id":"barcelona-week-la-plata","name":"Bar La Plata","coordinates":[41.3818,2.1799],"description":"Bar La Plata is the low-key Gothic bar stop for the week: simple, historic, fast, and food-adjacent. It is best used as a compact vermouth-and-bites pause before moving into the Born or waterfront.","hours":{"mon":"12:00 PM-12:30 AM","tue":"12:00 PM-12:30 AM","wed":"12:00 PM-12:30 AM","thu":"12:00 PM-1:30 AM","fri":"12:00 PM-2:00 AM","sat":"12:00 PM-2:00 AM","sun":"12:00 PM-12:00 AM"}},{"id":"barcelona-week-santa-maria","name":"Basílica de Santa Maria del Mar","coordinates":[41.3839,2.1822],"description":"Santa Maria del Mar anchors the El Born day with architecture that explains the neighborhood''s medieval merchant identity. Pair it with the Picasso Museum area, Ciutadella, or a cava stop nearby.","hours":{"mon":"9:00 AM-8:00 PM","tue":"9:00 AM-8:00 PM","wed":"9:00 AM-8:00 PM","thu":"9:00 AM-8:00 PM","fri":"9:00 AM-8:00 PM","sat":"9:00 AM-8:00 PM","sun":"9:00 AM-8:00 PM"}},{"id":"barcelona-week-paradiso","name":"Paradiso","coordinates":[41.3859,2.1822],"description":"Paradiso is the popular-bar slot for the Born night because a week gives you room to accept the queue and make the cocktail spectacle the event rather than a rushed afterthought.","hours":{"mon":"6:00 PM-12:30 AM","tue":"6:00 PM-12:30 AM","wed":"6:00 PM-1:00 AM","thu":"6:00 PM-1:30 AM","fri":"6:00 PM-2:30 AM","sat":"6:00 PM-2:30 AM","sun":"6:00 PM-12:00 AM"}},{"id":"barcelona-week-joan-miro","name":"Fundació Joan Miró","coordinates":[41.3686,2.1592],"description":"Fundació Joan Miró gives the Montjuïc day a focused art center before the route turns toward gardens, views, or Poble-sec. It is a smart midweek reset after denser old-city days.","hours":{"mon":"Closed","tue":"10:00 AM-7:00 PM","wed":"10:00 AM-7:00 PM","thu":"10:00 AM-7:00 PM","fri":"10:00 AM-7:00 PM","sat":"10:00 AM-7:00 PM","sun":"10:00 AM-7:00 PM"}},{"id":"barcelona-week-quimet-quimet","name":"Quimet & Quimet","coordinates":[41.3738,2.1635],"description":"Quimet & Quimet is the Poble-sec food-and-dive-bar bridge, with standing montaditos and bottles that fit a weeklong itinerary better than another formal dinner. Go early and let it launch a Carrer de Blai evening.","hours":{"mon":"12:00 PM-11:00 PM","tue":"12:00 PM-11:00 PM","wed":"12:00 PM-11:00 PM","thu":"12:00 PM-11:30 PM","fri":"12:00 PM-12:00 AM","sat":"12:00 PM-12:00 AM","sun":"12:00 PM-10:30 PM"}},{"id":"barcelona-week-apolo","name":"Sala Apolo","coordinates":[41.3752,2.1696],"description":"Sala Apolo closes the week with the city''s bigger nightlife energy: concerts, club programming, and a real reason to stay out late. It is the final category contrast after museums, restaurants, hostels, and small bars.","hours":{"mon":"10:00 PM-2:30 AM","tue":"10:00 PM-2:30 AM","wed":"10:00 PM-3:30 AM","thu":"10:00 PM-4:30 AM","fri":"10:00 PM-5:00 AM","sat":"10:00 PM-5:00 AM","sun":"10:00 PM-2:30 AM"}}],"sources":[{"name":"Barcelona Turisme","url":"https://www.barcelonaturisme.com"},{"name":"The Infatuation - Best Restaurants in Barcelona","url":"https://www.theinfatuation.com/barcelona/guides/best-restaurants-hotels-barcelona"},{"name":"Eater - Best Restaurants in Barcelona","url":"https://www.eater.com/maps/best-restaurants-barcelona-spain"},{"name":"MICHELIN Guide - Disfrutar","url":"https://guide.michelin.com/us/en/catalunya/barcelona/restaurant/disfrutar"},{"name":"Time Out - Best bars in Barcelona","url":"https://www.timeout.com/barcelona/bars-and-pubs/best-bars-in-barcelona"},{"name":"Hostelworld - Barcelona hostels","url":"https://www.hostelworld.com/st/hostels/europe/spain/barcelona/"},{"name":"Google Maps","url":"https://maps.google.com"}]}'::jsonb),
  ('list-gabriel-first-guide', 'gabriel-first-guide', 'Activities', 'United States', 'San Francisco', null, '{"id":"list-gabriel-first-guide","slug":"gabriel-first-guide","title":"SF Visitor Guide","description":"A first-time San Francisco route spanning waterfront landmarks, iconic parks, major museums, and city viewpoints worth planning around.","url":"https://maps.app.goo.gl/ipATDsbmTuXVr8hc9?g_st=ac","category":"Activities","location":{"city":"San Francisco","country":"United States","continent":"North America","scope":"city"},"creator":{"id":"user-gabriel-soyka","name":"Gabriel Soyka","avatar":"https://i.pravatar.cc/160?img=59"},"upvotes":1,"createdAt":"2026-04-21T00:00:00.000Z","submissionType":"guide","stops":[{"id":"gabriel-sf-ferry-building","name":"Ferry Building","coordinates":[37.7954425,-122.3936136],"description":"Historic Embarcadero landmark with standout local food vendors, bayfront promenades, and easy access to ferries and Market Street."},{"id":"gabriel-sf-fishermans-wharf","name":"Fisherman''s Wharf","coordinates":[37.8084354,-122.4157509],"description":"High-energy waterfront district for classic first-time sights, pier walks, and quick routes toward North Beach and the bay."},{"id":"gabriel-sf-palace-of-fine-arts","name":"Palace of Fine Arts","coordinates":[37.8029308,-122.4484231],"description":"Grand Beaux-Arts rotunda and lagoon setting that works best for golden-hour photos and a slower walk before sunset."},{"id":"gabriel-sf-alamo-square","name":"Alamo Square Park","coordinates":[37.7763694,-122.434819],"description":"One of the best skyline lawn views in the city, framed by the Painted Ladies and ideal for a short viewpoint stop."},{"id":"gabriel-sf-de-young","name":"de Young Museum","coordinates":[37.771469,-122.4686755],"description":"Major Golden Gate Park museum with strong permanent collections and a tower lookout that gives broad western-city views."},{"id":"gabriel-sf-legion-of-honor","name":"Legion of Honor","coordinates":[37.7845231,-122.5007596],"description":"Fine arts museum on the ocean edge with a calmer pace, dramatic approaches, and nearby access to Lands End trails."},{"id":"gabriel-sf-lombard","name":"Lombard St","coordinates":[37.8020179,-122.4195579],"description":"Iconic switchback block that is busy most of the day; best paired with a short uphill walk for better full-street views."},{"id":"gabriel-sf-vermont","name":"Vermont St (The real “Crookedest Street in the World.”)","coordinates":[37.7589957,-122.4039109],"description":"Local alternative to Lombard with tighter turns, fewer crowds, and a more neighborhood feel in Potrero Hill."},{"id":"gabriel-sf-bison-paddock","name":"Bison Paddock","coordinates":[37.7696864,-122.4982325],"description":"Unexpected Golden Gate Park stop where a small bison herd adds a quirky wildlife break on a west-side loop."},{"id":"gabriel-sf-amoeba","name":"Amoeba Music","coordinates":[37.7691734,-122.4526639],"description":"Legendary Haight record store with deep vinyl selection and strong local culture energy for an indoor break."},{"id":"gabriel-sf-rodeo-beach","name":"Rodeo Beach Coastal Trailhead","coordinates":[37.8322377,-122.5395782],"description":"Marin Headlands launch point for rugged coastal walks, sweeping Pacific views, and photogenic bridge-backdrop angles."},{"id":"gabriel-sf-duboce","name":"Duboce Park","coordinates":[37.7695967,-122.4333344],"description":"Compact neighborhood green space that works as a relaxed reset between Haight, Mission, and central transit lines."},{"id":"gabriel-sf-grandview","name":"Grandview Park","coordinates":[37.7564222,-122.4717361],"description":"Steep stair climb to a compact summit with wide city-to-ocean panoramas and one of SF’s strongest quick viewpoints."},{"id":"gabriel-sf-dolores","name":"Mission Dolores Park","coordinates":[37.7602015,-122.4267959],"description":"Flagship social park with broad downtown views, strong afternoon atmosphere, and easy walkability into the Mission."}],"sources":[{"name":"Google Maps shared list","url":"https://maps.app.goo.gl/ipATDsbmTuXVr8hc9?g_st=ac"}]}'::jsonb),
  ('list-gabriel-experience-dolores-sunset', 'gabriel-experience-dolores-sunset', 'Activities', 'United States', 'San Francisco', null, '{"id":"list-gabriel-experience-dolores-sunset","slug":"gabriel-experience-dolores-sunset","title":"Dolores Park Golden Hour","description":"Caught sunset on the upper slope with a full downtown skyline glow and a packed local after-work crowd.","url":"https://maps.google.com/?q=Mission+Dolores+Park+San+Francisco","category":"Activities","submissionType":"journal","journal":{"visitedAt":"2026-04-18","note":"Best around 6:30-7:30 PM with a light layer, then walked down Valencia for dinner."},"location":{"city":"San Francisco","country":"United States","continent":"North America","scope":"city"},"creator":{"id":"user-gabriel-soyka","name":"Gabriel Soyka","avatar":"https://i.pravatar.cc/160?img=59"},"upvotes":1,"createdAt":"2026-04-18T00:00:00.000Z","stops":[{"id":"gabriel-exp-dolores-stop","name":"Mission Dolores Park","coordinates":[37.7602015,-122.4267959],"description":"Sunset lawn session with skyline views."}],"sources":[{"name":"Personal experience","url":"https://maps.google.com/?q=Mission+Dolores+Park+San+Francisco"}]}'::jsonb),
  ('list-gabriel-experience-ferry-morning', 'gabriel-experience-ferry-morning', 'Activities', 'United States', 'San Francisco', null, '{"id":"list-gabriel-experience-ferry-morning","slug":"gabriel-experience-ferry-morning","title":"Ferry Building Morning Loop","description":"Started early at the Ferry Building, grabbed coffee, then walked north along the Embarcadero before crowds built.","url":"https://maps.google.com/?q=Ferry+Building+San+Francisco","category":"Activities","submissionType":"journal","journal":{"visitedAt":"2026-04-12","note":"Weekday mornings are easiest; great first stop before crossing into North Beach."},"location":{"city":"San Francisco","country":"United States","continent":"North America","scope":"city"},"creator":{"id":"user-gabriel-soyka","name":"Gabriel Soyka","avatar":"https://i.pravatar.cc/160?img=59"},"upvotes":1,"createdAt":"2026-04-12T00:00:00.000Z","stops":[{"id":"gabriel-exp-ferry-stop","name":"Ferry Building","coordinates":[37.7954425,-122.3936136],"description":"Early walk, food hall, waterfront start."}],"sources":[{"name":"Personal experience","url":"https://maps.google.com/?q=Ferry+Building+San+Francisco"}]}'::jsonb),
  ('list-gabriel-experience-headlands-wind', 'gabriel-experience-headlands-wind', 'Nature', 'United States', 'San Francisco', null, '{"id":"list-gabriel-experience-headlands-wind","slug":"gabriel-experience-headlands-wind","title":"Windy Marin Headlands Run","description":"Quick headlands run from Rodeo Beach trailhead with strong wind, dramatic coastline, and clear bridge-back views.","url":"https://maps.google.com/?q=Rodeo+Beach+Coastal+Trailhead","category":"Nature","submissionType":"journal","journal":{"visitedAt":"2026-03-30","note":"Bring a windbreaker even on sunny days; visibility changes fast."},"location":{"city":"San Francisco","country":"United States","continent":"North America","scope":"city"},"creator":{"id":"user-gabriel-soyka","name":"Gabriel Soyka","avatar":"https://i.pravatar.cc/160?img=59"},"upvotes":1,"createdAt":"2026-03-30T00:00:00.000Z","stops":[{"id":"gabriel-exp-headlands-stop","name":"Rodeo Beach Coastal Trailhead","coordinates":[37.8322377,-122.5395782],"description":"Short run with high-impact ocean views."}],"sources":[{"name":"Personal experience","url":"https://maps.google.com/?q=Rodeo+Beach+Coastal+Trailhead"}]}'::jsonb)
